// ----------------------------------------------------------------
// 🎯 Campaigns — admin UI for the campaigns + campaign_agents tables.
// Phase 1: list / create / edit / pause / delete.
// Distribution enforcement, automation hooks, and the conditional
// rules editor land in Phases 2-4 (see migrations/2026_05_08_campaigns.sql
// for the per-mode semantics).
// ----------------------------------------------------------------
const CAMPAIGN_MODES = [
  { value: 'on_demand',   label: 'On Demand',
    desc:  "Leads stay unassigned until an agent calls Pull. The system then assigns them in batches (size set below)." },
  { value: 'equal',       label: 'Equal',
    desc:  'New leads are distributed evenly across all agents so totals stay balanced over time.' },
  { value: 'round_robin', label: 'Round Robin',
    desc:  'Strict cursor — agent A, then B, then C, then back to A. Order is deterministic across server restarts.' },
  { value: 'percentage',  label: 'Percentage',
    desc:  'Each agent receives the percentage of new leads you set. The percentages must add up to 100.' },
  { value: 'conditional', label: 'Conditional',
    desc:  'Routes each lead by source / city / product / custom-field rules you define. (Editor lands in Phase 4.)' }
];
const CAMPAIGN_REMOVED_ACTIONS = [
  { value: 'pool',    label: 'Return to unassigned pool',
    desc:  "Their open leads go back into the pool to be redistributed by the campaign's mode." },
  { value: 'hidden',  label: 'Keep hidden until reassigned',
    desc:  'Their open leads stay assigned to that user but are hidden from every list until an admin reassigns them.' },
  { value: 'manager', label: 'Reassign to campaign manager',
    desc:  "Their open leads are handed to the manager set on the campaign." }
];

async function adminCampaigns(reload) {
  if (typeof reload !== 'function') reload = () => reload();
  const root = h('div', { class: 'admin-section' });
  root.appendChild(h('h3', {}, '🎯 Campaigns'));
  root.appendChild(h('p', { class: 'muted' },
    'Group leads under named campaigns and decide how each campaign distributes new leads to its agents. ' +
    'Phase 1 = create / edit / pause. Distribution enforcement, automation hooks (WhatsApp / Email on lead events), ' +
    'and conditional rules ship in follow-up phases.'
  ));

  let rows = [];
  try { rows = await api('api_campaigns_list'); } catch (e) {
    root.appendChild(h('div', { class: 'error-box' }, esc(e.message)));
    return root;
  }

  root.appendChild(h('div', { class: 'row gap', style: { marginBottom: '.75rem' } },
    h('button', { class: 'btn primary', onclick: () => openCampaignEditModal(null, () => reload()) },
      '+ Create campaign')
  ));

  if (!rows.length) {
    root.appendChild(h('div', { class: 'muted' }, 'No campaigns yet.'));
    return root;
  }

  const table = h('table', { class: 'data-table' });
  table.appendChild(h('thead', {},
    h('tr', {},
      h('th', {}, 'Name'),
      h('th', {}, 'Pipeline'),
      h('th', {}, 'Manager'),
      h('th', {}, 'Mode'),
      h('th', {}, 'Agents'),
      h('th', {}, 'Leads'),
      h('th', {}, 'Status'),
      h('th', {}, '')
    )
  ));
  const tbody = h('tbody', {});
  rows.forEach(r => {
    const modeLabel = (CAMPAIGN_MODES.find(m => m.value === r.distribution_mode) || {}).label || r.distribution_mode;
    tbody.appendChild(h('tr', {},
      h('td', {}, h('strong', {}, esc(r.name))),
      h('td', {}, esc(r.pipeline || '—')),
      h('td', {}, esc(r.manager_name || '—')),
      h('td', {}, modeLabel),
      h('td', {}, String(r.agent_count || 0)),
      h('td', {}, String(r.lead_count || 0)),
      h('td', {},
        Number(r.is_active) === 1
          ? h('span', { class: 'badge ok' }, 'Active')
          : h('span', { class: 'badge warn' }, 'Paused')
      ),
      h('td', { style: { textAlign: 'right' } },
        h('button', { class: 'btn sm',
          onclick: () => openCampaignEditModal(r, () => reload()) }, '✎ Edit'),
        ' ',
        h('button', { class: 'btn sm',
          onclick: async () => {
            try {
              await api('api_campaigns_pause', r.id, Number(r.is_active) === 1);
              reload();
            } catch (e) { toast(e.message, 'err'); }
          } }, Number(r.is_active) === 1 ? '⏸ Pause' : '▶ Resume'),
        ' ',
        h('button', { class: 'btn sm danger',
          onclick: async () => {
            if (!await confirmDialog(`Delete campaign "${r.name}"?`)) return;
            try { await api('api_campaigns_delete', r.id); toast('Deleted'); reload(); }
            catch (e) { toast(e.message, 'err'); }
          } }, '🗑')
      )
    ));
  });
  table.appendChild(tbody);
  root.appendChild(table);
  return root;
}

async function openCampaignEditModal(camp, onSaved) {
  const isNew = !camp;
  // Hydrate full record on edit so we have the agents list.
  if (!isNew && (!camp.agents || !camp.agents.length)) {
    try { camp = await api('api_campaigns_get', camp.id); } catch (e) { toast(e.message, 'err'); return; }
  }
  const users = (CRM.cache && CRM.cache.users) || (await api('api_users_list'));
  const activeUsers = users.filter(u => Number(u.is_active) !== 0);

  const m = h('div', { class: 'modal-backdrop',
    onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class: 'modal', style: { maxWidth: '640px' } });
  modal.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, isNew ? 'Create campaign' : 'Edit campaign'),
    h('button', { class: 'btn icon', onclick: () => m.remove() }, '✕')
  ));
  const body = h('div', { class: 'modal-body-wrap', style: { padding: '.25rem 0' } });

  // Name
  const nameI = h('input', { type: 'text', value: camp ? (camp.name || '') : '',
    placeholder: 'e.g., 11–12 Mar26 SR Imp School', style: { width: '100%' } });
  body.appendChild(h('label', {}, 'Name'));
  body.appendChild(nameI);

  // Pipeline (free-form text — no pipelines table yet)
  const pipeI = h('input', { type: 'text', value: camp ? (camp.pipeline || '') : '',
    placeholder: 'Optional · e.g., Pre-Sales', style: { width: '100%' } });
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Pipeline'));
  body.appendChild(pipeI);

  // ─── Lead Match Filter ──────────────────────────────────────────
  // Defines which leads auto-attach to this campaign when they're
  // created (from Make / IndiaMART / manual entry / CSV / anywhere).
  // All rules AND-joined. Field dropdown includes every active custom
  // field as cf_<key>, so e.g. 'cf_state contains Karnataka' works.
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Lead match filter — leads that should auto-join this campaign'));
  body.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem', marginBottom: '.4rem' } },
    'When a lead matches ALL rules below, it auto-attaches to this campaign and the distribution mode (above) decides which agent gets it. Leave empty to skip auto-attach — leads must then be assigned manually or via campaign_id on lead create.'));
  const matchWrap = h('div', { id: 'match-filter-wrap', style: { display: 'grid', gap: '.4rem' } });
  let _matchRules = (() => {
    if (!camp || camp.match_filter == null) return [];
    if (Array.isArray(camp.match_filter)) return camp.match_filter;
    if (typeof camp.match_filter === 'string') {
      try { return JSON.parse(camp.match_filter) || []; } catch (_) { return []; }
    }
    return [];
  })();
  function _renderMatchRules() {
    matchWrap.replaceChildren();
    const stdFields = ['source', 'product', 'city', 'state', 'pincode', 'country', 'company', 'name', 'phone', 'email', 'notes', 'tags', 'source_ref', 'utm_source', 'utm_campaign'];
    const cfList = (CRM.cache.customFields || []).filter(c => Number(c.is_active) !== 0 && c.key);
    const fieldOpts = [
      ...stdFields.map(v => ({ value: v, label: v })),
      ...cfList.map(c => ({ value: 'cf_' + c.key, label: (c.label || c.key) + '  (custom)' }))
    ];
    const opOpts = [
      { value: 'equals',       label: 'equals' },
      { value: 'not_equals',   label: 'is not' },
      { value: 'contains',     label: 'contains' },
      { value: 'starts_with',  label: 'starts with' },
      { value: 'ends_with',    label: 'ends with' },
      { value: 'is_empty',     label: 'is empty' },
      { value: 'is_not_empty', label: 'is not empty' }
    ];
    _matchRules.forEach((rule, idx) => {
      const fSel = h('select', { style: { minWidth: '140px' } },
        ...fieldOpts.map(o => h('option', { value: o.value, selected: o.value === rule.field ? '' : null }, o.label)));
      const oSel = h('select', { style: { minWidth: '140px' } },
        ...opOpts.map(o => h('option', { value: o.value, selected: o.value === (rule.op || rule.operator) ? '' : null }, o.label)));
      const vInp = h('input', { type: 'text', value: rule.value || '', placeholder: 'Value',
        style: { minWidth: '120px', flex: 1 } });
      const rmBtn = h('button', { type: 'button', class: 'btn sm danger',
        onclick: () => { _matchRules.splice(idx, 1); _renderMatchRules(); } }, '🗑');
      const sync = () => {
        _matchRules[idx] = { field: fSel.value, op: oSel.value, value: vInp.value };
        // Hide value input for is_empty / is_not_empty operators
        const opv = oSel.value;
        vInp.style.display = (opv === 'is_empty' || opv === 'is_not_empty') ? 'none' : '';
      };
      [fSel, oSel, vInp].forEach(el => el.addEventListener('change', sync));
      vInp.addEventListener('input', sync);
      sync();
      const row = h('div', { style: { display: 'flex', gap: '.3rem', alignItems: 'center', flexWrap: 'wrap' } },
        idx > 0 ? h('span', { style: { fontSize: '.75rem', color: '#64748b', fontWeight: 600 } }, 'AND') : null,
        fSel, oSel, vInp, rmBtn);
      matchWrap.appendChild(row);
    });
    matchWrap.appendChild(h('button', {
      type: 'button', class: 'btn sm', style: { justifySelf: 'start' },
      onclick: () => { _matchRules.push({ field: 'source', op: 'equals', value: '' }); _renderMatchRules(); }
    }, '+ Add rule'));
  }
  _renderMatchRules();
  body.appendChild(matchWrap);

  // Manager
  const managerS = h('select', { style: { width: '100%' } },
    h('option', { value: '' }, '— Choose manager —'),
    ...activeUsers.map(u => h('option', { value: String(u.id) },
      `${u.name} · ${u.role}`))
  );
  if (camp && camp.manager_user_id) managerS.value = String(camp.manager_user_id);
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Who will manage this campaign?'));
  body.appendChild(managerS);

  // Agents (multi-select via checkboxes — easier on mobile than a multi-select)
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Agents on this campaign'));
  const agentBox = h('div', {
    style: { border: '1px solid #e2e8f0', borderRadius: '8px', padding: '.5rem',
             maxHeight: '220px', overflowY: 'auto', display: 'grid',
             gridTemplateColumns: '1fr', gap: '.25rem' }
  });
  const existingAgentIds = new Set((camp && camp.agents || []).filter(a => Number(a.is_active) === 1).map(a => Number(a.user_id)));
  const existingAgentWeights = new Map((camp && camp.agents || []).map(a => [Number(a.user_id), Number(a.weight_pct || 100)]));
  const agentRows = activeUsers.map(u => {
    const cb = h('input', { type: 'checkbox', value: String(u.id) });
    cb.checked = existingAgentIds.has(u.id);
    const wInput = h('input', { type: 'number', min: '0', max: '100', step: '1',
      value: String(existingAgentWeights.get(u.id) || 100),
      style: { width: '70px', display: 'none' } });
    const row = h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem' } },
      cb, h('span', { style: { flex: 1 } }, `${u.name} · ${u.role}`), wInput, h('span', { style: { display: 'none', color: '#64748b' } }, '%'));
    row.querySelectorAll('span')[1].style.display = 'none';   // % label hidden by default
    row._cb = cb; row._w = wInput; row._userId = u.id;
    agentBox.appendChild(row);
    return row;
  });

  // Distribution mode
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Lead distribution'));
  const modeWrap = h('div', { style: { display: 'grid', gap: '.4rem' } });
  const modeRadios = CAMPAIGN_MODES.map(m => {
    const radio = h('input', { type: 'radio', name: 'cmode', value: m.value });
    radio.checked = (camp && camp.distribution_mode === m.value) || (!camp && m.value === 'on_demand');
    const lab = h('label', {
      style: { display: 'block', border: '1px solid #e2e8f0', borderRadius: '8px',
               padding: '.55rem .7rem', cursor: 'pointer' }
    },
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem' } },
        radio, h('strong', {}, m.label)),
      h('div', { class: 'muted', style: { fontSize: '.85rem', marginLeft: '1.4rem', marginTop: '.15rem' } }, m.desc)
    );
    modeWrap.appendChild(lab);
    return radio;
  });
  body.appendChild(modeWrap);

  // Toggle weight inputs visibility based on selected mode
  function refreshWeightVisibility() {
    const sel = modeRadios.find(r => r.checked);
    const isPct = sel && sel.value === 'percentage';
    agentRows.forEach(r => {
      r._w.style.display = isPct ? 'inline-block' : 'none';
      r.querySelectorAll('span')[1].style.display = isPct ? 'inline' : 'none';
    });
  }
  modeRadios.forEach(r => r.addEventListener('change', refreshWeightVisibility));
  body.appendChild(agentBox);
  // Re-call after agentBox is appended so weight inputs reflect initial mode
  refreshWeightVisibility();

  // Pull batch settings (only relevant for on_demand but always saved)
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Pull batch — leads given on each "Start Calling"'));
  const pullBatch = h('input', { type: 'number', min: '1', max: '500',
    value: String((camp && camp.pull_batch_size) || 10), style: { width: '120px' } });
  body.appendChild(pullBatch);
  body.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem', margin: '.2rem 0' } },
    'Used by On Demand mode. Round Robin / Equal / Percentage modes ignore this and assign on lead create.'));

  const requireOld = h('input', { type: 'checkbox' });
  requireOld.checked = camp && Number(camp.pull_require_old_updated) === 1;
  const oldThreshold = h('input', { type: 'number', min: '0', max: '43200',
    value: String((camp && camp.pull_old_threshold_minutes) || 60), style: { width: '100px' } });
  body.appendChild(h('label', { style: { display: 'flex', alignItems: 'center', gap: '.5rem', marginTop: '.5rem' } },
    requireOld,
    h('span', {}, 'Block pull until previously-pulled leads older than '),
    oldThreshold,
    h('span', {}, ' minutes are updated')
  ));

  // Conditional rules editor — only visible when distribution_mode='conditional'.
  // Each rule is { if: { <field>: <expected> | { op, value } }, then: { user_id } }.
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'Conditional rules'));
  const rulesNote = h('div', { class: 'muted', style: { fontSize: '.85rem', marginBottom: '.4rem' } },
    'Only used when Distribution mode = Conditional. The first rule that matches a lead wins; if none match, the lead is round-robined among active agents.');
  body.appendChild(rulesNote);
  const rulesWrap = h('div', { id: 'rules-wrap', style: { display: 'grid', gap: '.4rem' } });
  let currentRules = (() => {
    if (!camp || camp.conditional_rules == null) return [];
    if (Array.isArray(camp.conditional_rules)) return camp.conditional_rules;
    if (typeof camp.conditional_rules === 'string') {
      try { return JSON.parse(camp.conditional_rules) || []; } catch (_) { return []; }
    }
    return [];
  })();
  function renderRules() {
    rulesWrap.replaceChildren();
    const fieldOpts = [
      { value: 'source',       label: 'Source' },
      { value: 'city',         label: 'City' },
      { value: 'state',        label: 'State' },
      { value: 'product_id',   label: 'Product' },
      { value: 'tags',         label: 'Tags' },
      { value: 'utm_source',   label: 'UTM source' },
      { value: 'utm_campaign', label: 'UTM campaign' }
    ];
    const opOpts = [
      { value: 'eq',          label: 'equals' },
      { value: 'not_eq',      label: 'is not' },
      { value: 'in',          label: 'is one of (comma-sep)' },
      { value: 'contains',    label: 'contains' },
      { value: 'starts_with', label: 'starts with' }
    ];
    currentRules.forEach((rule, idx) => {
      const ifBlock = rule.if || {};
      const firstField = Object.keys(ifBlock)[0] || 'source';
      const cond = ifBlock[firstField];
      const isObj = cond && typeof cond === 'object' && !Array.isArray(cond);
      const op    = isObj ? (cond.op || 'eq') : (Array.isArray(cond) ? 'in' : 'eq');
      const value = isObj ? cond.value : (Array.isArray(cond) ? cond.join(', ') : (cond == null ? '' : String(cond)));
      const targetUserId = (rule.then && rule.then.user_id) ? Number(rule.then.user_id) : '';

      const fieldSel = h('select', { style: { minWidth: '120px' } },
        ...fieldOpts.map(f => h('option', { value: f.value, selected: f.value === firstField ? '' : null }, f.label)));
      const opSel = h('select', { style: { minWidth: '120px' } },
        ...opOpts.map(o => h('option', { value: o.value, selected: o.value === op ? '' : null }, o.label)));
      const valI  = h('input', { type: 'text', value: Array.isArray(value) ? value.join(', ') : value, placeholder: 'Value', style: { minWidth: '120px', flex: 1 } });
      const userSel = h('select', { style: { minWidth: '160px' } },
        h('option', { value: '' }, '— Pick agent —'),
        ...(activeUsers || []).map(u => h('option', { value: String(u.id), selected: Number(u.id) === Number(targetUserId) ? '' : null }, `${u.name} · ${u.role}`)));
      const removeBtn = h('button', { type: 'button', class: 'btn sm danger',
        onclick: () => { currentRules.splice(idx, 1); renderRules(); } }, '🗑');

      // Persist edits inline so the form submit reads from currentRules
      const sync = () => {
        const f  = fieldSel.value;
        const o  = opSel.value;
        const v  = valI.value;
        const condOut = o === 'in'
          ? { op: 'in', value: v.split(',').map(s => s.trim()).filter(Boolean) }
          : (o === 'eq' ? v : { op: o, value: v });
        currentRules[idx] = {
          if:   { [f]: condOut },
          then: { user_id: userSel.value ? Number(userSel.value) : null }
        };
      };
      [fieldSel, opSel, valI, userSel].forEach(el => el.addEventListener('change', sync));
      valI.addEventListener('input', sync);

      const row = h('div', {
        style: { display: 'flex', gap: '.35rem', flexWrap: 'wrap', alignItems: 'center',
                 border: '1px solid #e2e8f0', borderRadius: '8px', padding: '.45rem' } },
        h('span', { class: 'muted', style: { fontSize: '.78rem' } }, 'If '),
        fieldSel, opSel, valI,
        h('span', { class: 'muted', style: { fontSize: '.78rem' } }, ' → assign to '),
        userSel,
        removeBtn
      );
      rulesWrap.appendChild(row);
    });
    if (!currentRules.length) {
      rulesWrap.appendChild(h('div', { class: 'muted', style: { fontSize: '.85rem' } },
        'No rules yet — click "Add rule" to create one.'));
    }
  }
  const addRuleBtn = h('button', { type: 'button', class: 'btn sm', style: { width: 'fit-content' },
    onclick: () => { currentRules.push({ if: { source: '' }, then: { user_id: null } }); renderRules(); }
  }, '+ Add rule');
  body.appendChild(rulesWrap);
  body.appendChild(addRuleBtn);
  renderRules();

  // Toggle visibility of the rules section based on selected mode
  function refreshRulesVisibility() {
    const sel = modeRadios.find(r => r.checked);
    const isCond = sel && sel.value === 'conditional';
    rulesNote.style.display = isCond ? '' : 'none';
    rulesWrap.style.display = isCond ? 'grid' : 'none';
    addRuleBtn.style.display = isCond ? '' : 'none';
  }
  modeRadios.forEach(r => r.addEventListener('change', refreshRulesVisibility));
  refreshRulesVisibility();

  // Removed user action
  body.appendChild(h('label', { style: { marginTop: '.6rem' } }, 'When an agent is removed from this campaign'));
  const ruWrap = h('div', { style: { display: 'grid', gap: '.4rem' } });
  const ruRadios = CAMPAIGN_REMOVED_ACTIONS.map(a => {
    const radio = h('input', { type: 'radio', name: 'cruact', value: a.value });
    radio.checked = (camp && camp.removed_user_action === a.value) || (!camp && a.value === 'pool');
    const lab = h('label', {
      style: { display: 'block', border: '1px solid #e2e8f0', borderRadius: '8px',
               padding: '.55rem .7rem', cursor: 'pointer' }
    },
      h('div', { style: { display: 'flex', alignItems: 'center', gap: '.4rem' } },
        radio, h('strong', {}, a.label)),
      h('div', { class: 'muted', style: { fontSize: '.85rem', marginLeft: '1.4rem', marginTop: '.15rem' } }, a.desc)
    );
    ruWrap.appendChild(lab);
    return radio;
  });
  body.appendChild(ruWrap);

  modal.appendChild(body);
  const foot = h('div', { class: 'modal-foot' },
    h('button', { class: 'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class: 'btn primary', onclick: async () => {
      try {
        const mode = (modeRadios.find(r => r.checked) || {}).value || 'on_demand';
        const removedAction = (ruRadios.find(r => r.checked) || {}).value || 'pool';
        const agents = agentRows.filter(r => r._cb.checked).map(r => ({
          user_id:    r._userId,
          weight_pct: Number(r._w.value || 100)
        }));
        const payload = {
          id: camp ? camp.id : undefined,
          name: nameI.value.trim(),
          pipeline: pipeI.value.trim() || null,
          manager_user_id: managerS.value ? Number(managerS.value) : null,
          distribution_mode: mode,
          pull_batch_size: Number(pullBatch.value || 10),
          pull_initial_count: Number(pullBatch.value || 10),
          pull_require_old_updated: requireOld.checked,
          pull_old_threshold_minutes: Number(oldThreshold.value || 60),
          removed_user_action: removedAction,
          conditional_rules: mode === 'conditional' ? currentRules : null,
          // Lead match filter — only persist rules that have a field; for
          // is_empty/is_not_empty operators, value is irrelevant.
          match_filter: (_matchRules || []).filter(r =>
            r && r.field && (
              r.op === 'is_empty' || r.op === 'is_not_empty' ||
              (r.value !== undefined && r.value !== '')
            )
          ),
          agents
        };
        if (!payload.name) { toast('Name is required', 'err'); return; }
        await api('api_campaigns_save', payload);
        if (CRM.cache) CRM.cache.campaigns = null;
        toast('Saved');
        m.remove();
        if (typeof onSaved === 'function') onSaved();
      } catch (e) { toast(e.message, 'err'); }
    } }, 'Save')
  );
  modal.appendChild(foot);
  m.appendChild(modal);
  document.body.appendChild(m);
}


// ----------------------------------------------------------------
// 🧭 Menu order — admin reorders the sidebar nav groups.
// Persists as a CSV of group labels in config key SIDEBAR_NAV_GROUP_ORDER.
// Reload the page after saving to see the new order applied.
// ----------------------------------------------------------------
async function adminMenuOrder() {
  const root = h('div', { class: 'admin-section' });
  root.appendChild(h('h3', {}, '🧭 Menu order'));
  root.appendChild(h('p', { class: 'muted' },
    'Drag — actually, click ▲▼ — to reorder the sidebar groups. The Dashboard pinned item always stays at the top. Reload after saving for the change to apply.'));

  const cfg = await api('api_admin_getConfig');
  // Source of truth for what groups EXIST is NAV_GROUPS itself; we only
  // store the ordered list of labels.
  const existingLabels = NAV_GROUPS.filter(g => g.label).map(g => g.label);
  const savedOrder = String(cfg.SIDEBAR_NAV_GROUP_ORDER || '').split(',').map(s => s.trim()).filter(Boolean);
  // Stitch saved order with any new groups that aren't in saved list
  let order = savedOrder.filter(l => existingLabels.includes(l));
  existingLabels.forEach(l => { if (!order.includes(l)) order.push(l); });

  const list = h('div', { style: { display: 'grid', gap: '.4rem', maxWidth: '420px' } });
  function renderList() {
    list.replaceChildren();
    order.forEach((label, idx) => {
      const group = NAV_GROUPS.find(g => g.label === label);
      list.appendChild(h('div', {
        style: { display: 'flex', alignItems: 'center', gap: '.5rem',
                 background: '#fff', border: '1px solid #e2e8f0',
                 borderRadius: '8px', padding: '.55rem .75rem' } },
        h('span', { style: { fontSize: '1.1rem' } }, group ? (group.icon || '') : ''),
        h('span', { style: { flex: 1, fontWeight: 600 } }, label),
        h('button', { class: 'btn sm ghost', onclick: () => { if (idx > 0) { [order[idx-1], order[idx]] = [order[idx], order[idx-1]]; renderList(); } } }, '▲'),
        h('button', { class: 'btn sm ghost', onclick: () => { if (idx < order.length - 1) { [order[idx+1], order[idx]] = [order[idx], order[idx+1]]; renderList(); } } }, '▼')
      ));
    });
  }
  renderList();
  root.appendChild(list);

  root.appendChild(h('div', { style: { marginTop: '.8rem', display: 'flex', gap: '.5rem' } },
    h('button', { class: 'btn primary',
      onclick: async () => {
        try {
          await api('api_admin_setConfig', { SIDEBAR_NAV_GROUP_ORDER: order.join(',') });
          toast('Saved — reload to see the new order');
        } catch (e) { toast(e.message, 'err'); }
      } }, '💾 Save order'),
    h('button', { class: 'btn ghost',
      onclick: () => { order = existingLabels.slice(); renderList(); } }, 'Reset to default')
  ));

  return root;
}

async function adminPullLeads() {
  const cfg = await api('api_admin_getConfig');
  const root = h('div', { class: 'admin-section' });
  root.appendChild(h('h3', {}, '📥 Lead Pull'));
  root.appendChild(h('p', { class: 'muted' },
    'Lets non-admin users self-claim free leads (assigned_to IS NULL) from the pool. ' +
    'Admin-pre-assigned leads count toward the same per-pull budget. ' +
    'See docs/features/PULL-LEADS.md.'));

  // We need the dynamic roles list for the role picker.
  const allRoles = (await _rolesForSelect()).filter(r => r.value !== 'admin');
  const enabledRoles = String(cfg.LEAD_PULL_ENABLED_ROLES || 'sales,team_leader,manager')
    .split(',').map(s => s.trim()).filter(Boolean);

  const form = h('div', { class: 'form-grid' });
  const enabled = h('input', { type: 'checkbox', id: 'lp-enabled' });
  enabled.checked = String(cfg.LEAD_PULL_ENABLED ?? '1') === '1';
  form.appendChild(h('label', {}, enabled, ' Pull Leads enabled'));

  const initial = h('input', { type: 'number', id: 'lp-initial', min: '0', max: '500',
    value: String(cfg.LEAD_PULL_INITIAL_COUNT || '20') });
  form.appendChild(h('label', {}, 'Initial pull count (first time): ', initial,
    h('div', { class: 'muted small' }, 'How many leads a user gets the very first time they pull.')));

  const subseq = h('input', { type: 'number', id: 'lp-subseq', min: '0', max: '500',
    value: String(cfg.LEAD_PULL_SUBSEQUENT_COUNT || '5') });
  form.appendChild(h('label', {}, 'Subsequent pull count: ', subseq,
    h('div', { class: 'muted small' }, 'How many leads each later pull claims.')));

  const roleBox = h('div', { class: 'role-checks' });
  allRoles.forEach(r => {
    const cb = h('input', { type: 'checkbox', value: r.value, id: 'lp-role-' + r.value });
    cb.checked = enabledRoles.includes(r.value);
    roleBox.appendChild(h('label', { class: 'inline' }, cb, ' ' + r.label));
  });
  form.appendChild(h('label', {}, 'Allowed roles: ', roleBox,
    h('div', { class: 'muted small' }, 'Admins can never use Pull. List comes from Settings → 📛 Roles.')));

  const order = h('select', { id: 'lp-order' },
    h('option', { value: 'oldest' }, 'Oldest first (FIFO)'),
    h('option', { value: 'newest' }, 'Newest first (LIFO)')
  );
  order.value = String(cfg.LEAD_PULL_ORDER || 'oldest');
  form.appendChild(h('label', {}, 'Pull order: ', order,
    h('div', { class: 'muted small' }, 'Oldest-first stops fresh leads from going stale.')));

  root.appendChild(form);

  const save = h('button', { class: 'btn primary', onclick: async () => {
    const checkedRoles = Array.from(roleBox.querySelectorAll('input[type=checkbox]'))
      .filter(c => c.checked).map(c => c.value);
    const patch = {
      LEAD_PULL_ENABLED:           enabled.checked ? '1' : '0',
      LEAD_PULL_INITIAL_COUNT:     String(Math.max(0, parseInt(initial.value, 10) || 0)),
      LEAD_PULL_SUBSEQUENT_COUNT:  String(Math.max(0, parseInt(subseq.value, 10) || 0)),
      LEAD_PULL_ENABLED_ROLES:     checkedRoles.join(','),
      LEAD_PULL_ORDER:             order.value === 'newest' ? 'newest' : 'oldest'
    };
    try { await api('api_admin_setConfig', patch); toast('Lead Pull settings saved', 'ok'); }
    catch (e) { toast(e.message, 'err'); }
  } }, 'Save');
  root.appendChild(h('div', { class: 'form-actions' }, save));
  return root;
}

/**
 * Admin → Danger zone tab. Currently hosts the "Wipe HR data" tool.
 *
 * Lets the admin permanently delete all rows in the Leaves, Tasks,
 * Attendance, and/or Salary tables. Lead/customer/user data is NOT
 * touched. Requires the admin to type "WIPE-NOW" exactly into the
 * confirmation field — anything else is rejected server-side.
 */
async function adminDangerZone() {
  const wrap = h('div', {});
  const card = h('div', { class: 'card', style: { borderLeft: '4px solid #dc2626' } });
  card.appendChild(h('h4', { style: { marginTop: 0, color: '#dc2626' } }, '🛑 Wipe HR data'));
  card.appendChild(h('p', { class: 'muted' },
    'Permanently delete all rows in the selected categories. ',
    h('b', {}, 'This cannot be undone.'),
    ' Lead, customer, and user accounts are not touched — only HR-side data.'
  ));

  const cats = [
    { key: 'leaves',     label: 'Leaves data',     desc: 'Every applied/approved/rejected leave record' },
    { key: 'tasks',      label: 'Tasks data',      desc: 'All tasks created in the Tasks module' },
    { key: 'attendance', label: 'Attendance data', desc: 'Daily check-in/check-out logs + the linked location pings' },
    { key: 'salary',     label: 'Salary data',     desc: 'Monthly salary records (the user.monthly_salary base figure on each user is preserved)' }
  ];
  const checks = {};
  cats.forEach(c => {
    checks[c.key] = h('input', { type: 'checkbox', value: c.key });
    card.appendChild(h('label', { style: { display: 'flex', gap: '.5rem', alignItems: 'flex-start', padding: '.4rem 0' } },
      checks[c.key],
      h('span', {},
        h('b', {}, c.label),
        h('div', { class: 'muted', style: { fontSize: '.78rem' } }, c.desc)
      )
    ));
  });

  const confirmInput = h('input', { type: 'text', placeholder: 'Type WIPE-NOW to confirm', autocomplete: 'off',
    style: { fontFamily: 'monospace', letterSpacing: '.05em' } });
  card.appendChild(h('div', { class: 'f-row full', style: { marginTop: '1rem' } },
    h('label', {}, 'Confirmation phrase'),
    confirmInput
  ));
  card.appendChild(h('div', { class: 'actions', style: { marginTop: '.5rem' } },
    h('button', { class: 'btn danger', onclick: async () => {
      const picked = cats.filter(c => checks[c.key].checked).map(c => c.key);
      if (!picked.length) { toast('Pick at least one category to wipe', 'err'); return; }
      const phrase = confirmInput.value;
      if (phrase !== 'WIPE-NOW') {
        toast('Type WIPE-NOW exactly to confirm — case + dash matter', 'err');
        confirmInput.focus();
        return;
      }
      if (!await confirmDialog(`Permanently delete: ${picked.join(', ')}? This cannot be undone.`)) return;
      try {
        const r = await api('api_admin_wipeHrData', picked, phrase);
        const msg = Object.entries(r.deleted || {})
          .map(([k, v]) => `${k}: ${v}`)
          .join(' · ');
        toast('Wiped — ' + (msg || 'done'));
        confirmInput.value = '';
        cats.forEach(c => { checks[c.key].checked = false; });
      } catch (e) { toast(e.message, 'err'); }
    } }, '🗑️ Wipe selected data')
  ));

  wrap.appendChild(card);
  return wrap;
}

/**
 * Admin → Integrations tab. Two sections:
 *  1. Lead-source webhooks — copy-paste URL per vendor (IndiaMART,
 *     MagicBricks, JustDial, TradeIndia, 99acres, Housing).
 *  2. Google Sheet sync — manage connected sheets.
 */
/**
 * 📡 Webhook logs — admin view of every inbound /hook/* request.
 *
 * Shows the most recent webhook hits (website / Pabbly / Make.com / Meta /
 * lead-source vendors) with timestamp, source IP, HTTP status, and an
 * inline preview of the body. Click a row to expand the full payload +
 * response so admins can verify field mappings against what was actually
 * delivered.
 *
 * Per-tenant: each tenant's webhook_logs table is queried via the existing
 * tenantStorage pool, so admins only see their own tenant's events.
 */

async function adminPendingCalls() {
  // Manual-mode dashboard: lists every call_event with no linked lead so
  // admin can review + bulk-convert. Also surfaces the Auto/Manual toggle
  // so the admin can switch modes here without going to Settings.
  const wrap = h('div', {});

  // ── Mode-toggle card ─────────────────────────────────────────────
  const modeCard = h('div', { class: 'card' });
  modeCard.appendChild(h('h4', {}, '\uD83D\uDD27 Call-to-lead mode'));
  modeCard.appendChild(h('p', { class: 'muted' },
    'Auto — every incoming/missed call from an unknown number instantly creates a lead. ',
    'Manual — calls are logged but you decide which ones become leads (bulk-convert below).'));
  const modeRow = h('div', { style: { display: 'flex', gap: '.8rem', flexWrap: 'wrap' } });
  let currentMode = 'auto';
  try {
    const cfg = await api('api_admin_getConfig');
    currentMode = String(cfg.CALLS_AUTOLEAD_MODE || 'auto').toLowerCase();
  } catch (_) {}
  function makeRadio(val, label, desc) {
    const id = 'autolead-mode-' + val;
    const input = h('input', { type: 'radio', name: 'autolead-mode', id, value: val, checked: currentMode === val ? 'checked' : null });
    input.onchange = async () => {
      try {
        await api('api_admin_saveConfig', { CALLS_AUTOLEAD_MODE: val });
        toast('Switched to ' + val.toUpperCase() + ' mode', 'ok');
        currentMode = val;
      } catch (e) { toast('Save failed: ' + e.message, 'err'); }
    };
    return h('label', { for: id, style: { display: 'flex', gap: '.4rem', alignItems: 'flex-start', maxWidth: '300px', padding: '.5rem .7rem', border: '1px solid #e2e8f0', borderRadius: '8px', cursor: 'pointer' } },
      input,
      h('div', {}, h('b', {}, label), h('div', { class: 'muted', style: { fontSize: '.78rem' } }, desc))
    );
  }
  modeRow.appendChild(makeRadio('auto',   '\u2728 Auto',  'New numbers become leads instantly.'));
  modeRow.appendChild(makeRadio('manual', '\uD83C\uDFAF Manual', 'Review + pick which calls to convert.'));
  modeCard.appendChild(modeRow);
  wrap.appendChild(modeCard);

  // ── Pending calls list ─────────────────────────────────────────────
  const listCard = h('div', { class: 'card' });
  listCard.appendChild(h('h4', {}, '\u23F3 Pending calls — no lead yet'));
  const toolbar = h('div', { style: { display: 'flex', flexWrap: 'wrap', gap: '.5rem', alignItems: 'center', marginBottom: '.5rem' } });
  const daysSel = h('select', {},
    h('option', { value: 7 },  'Last 7 days'),
    h('option', { value: 30, selected: 'selected' }, 'Last 30 days'),
    h('option', { value: 90 }, 'Last 90 days')
  );
  const refreshBtn = h('button', { class: 'btn sm' }, '\u27F3 Refresh');
  const convertBtn = h('button', { class: 'btn primary sm', disabled: 'disabled' }, '\uD83D\uDCDE Convert selected to leads');
  const selectAllBox = h('input', { type: 'checkbox' });
  toolbar.appendChild(h('label', {}, selectAllBox, ' Select all'));
  toolbar.appendChild(daysSel);
  toolbar.appendChild(refreshBtn);
  toolbar.appendChild(convertBtn);
  listCard.appendChild(toolbar);

  const listHost = h('div', {}, h('div', { class: 'muted' }, 'Loading\u2026'));
  listCard.appendChild(listHost);
  wrap.appendChild(listCard);

  let _rows = [];
  let _selected = new Set();

  function updateConvertBtn() {
    convertBtn.disabled = _selected.size ? null : 'disabled';
    convertBtn.textContent = _selected.size
      ? '\uD83D\uDCDE Convert ' + _selected.size + ' to lead' + (_selected.size === 1 ? '' : 's')
      : '\uD83D\uDCDE Convert selected to leads';
  }

  async function load() {
    listHost.innerHTML = '<div class="muted">Loading\u2026</div>';
    _selected = new Set();
    selectAllBox.checked = false;
    updateConvertBtn();
    try {
      _rows = await api('api_call_events_pending', { days: Number(daysSel.value) || 30, limit: 200 });
    } catch (e) {
      listHost.innerHTML = '<div class="error-box">' + esc(e.message) + '</div>';
      return;
    }
    if (!_rows.length) {
      listHost.innerHTML = '';
      listHost.appendChild(h('div', { class: 'muted', style: { padding: '1rem' } },
        '\u2728 No pending calls. Every recent call is already attached to a lead.'));
      return;
    }
    const tbl = h('table', { class: 'tbl' });
    tbl.appendChild(h('thead', {}, h('tr', {},
      h('th', {}, ''),
      h('th', {}, 'When'),
      h('th', {}, 'Direction'),
      h('th', {}, 'Phone'),
      h('th', {}, 'Rep'),
      h('th', {}, 'Duration')
    )));
    const body = h('tbody', {});
    const dirIcon = { in: '\uD83D\uDCE5', out: '\uD83D\uDCE4', missed: '\u2757', outgoing: '\uD83D\uDCE4' };
    _rows.forEach(r => {
      const cb = h('input', { type: 'checkbox', value: r.id });
      cb.onchange = () => {
        if (cb.checked) _selected.add(r.id); else _selected.delete(r.id);
        updateConvertBtn();
      };
      const tr = h('tr', {},
        h('td', {}, cb),
        h('td', { class: 'muted', style: { whiteSpace: 'nowrap' } }, fmtDate(r.created_at, 'relative')),
        h('td', {}, (dirIcon[r.direction] || '\uD83D\uDCDE') + ' ' + (r.direction || '')),
        h('td', { style: { fontFamily: 'monospace' } }, r.phone || ''),
        h('td', {}, r.rep_name || '\u2014'),
        h('td', { class: 'muted' }, r.duration_s ? r.duration_s + 's' : '')
      );
      body.appendChild(tr);
    });
    tbl.appendChild(body);
    listHost.innerHTML = '';
    listHost.appendChild(tbl);
  }

  selectAllBox.onchange = () => {
    _selected = new Set();
    listHost.querySelectorAll('input[type=checkbox][value]').forEach(cb => {
      cb.checked = selectAllBox.checked;
      if (cb.checked) _selected.add(Number(cb.value));
    });
    updateConvertBtn();
  };
  refreshBtn.onclick = load;
  daysSel.onchange = load;
  convertBtn.onclick = async () => {
    if (!_selected.size) return;
    if (!confirm('Convert ' + _selected.size + ' selected call(s) to leads?\n\nDuplicates (same number) are merged into one lead.')) return;
    convertBtn.disabled = 'disabled'; convertBtn.textContent = 'Converting\u2026';
    try {
      const r = await api('api_call_events_convertToLeads', [..._selected]);
      const msg = r.leads_created + ' lead(s) created'
                + (r.skipped ? ', ' + r.skipped + ' skipped (already linked)' : '');
      toast(msg, 'ok');
      await load();
    } catch (e) { toast('Convert failed: ' + e.message, 'err'); }
    updateConvertBtn();
  };
  load();

  return wrap;
}

async function adminRecordingDiag() {
  const wrap = h('div', {});
  const toolbar = h('div', { class: 'toolbar', style: { display: 'flex', gap: '.5rem', alignItems: 'center', flexWrap: 'wrap' } });
  const recIdInput = h('input', { type: 'number', placeholder: 'Filter by recording ID (optional)', style: { width: '260px' } });
  const refreshBtn = h('button', { class: 'btn' }, '⟳ Refresh');
  const ffStatusBtn = h('button', { class: 'btn' }, '🔧 Check ffmpeg');
  toolbar.appendChild(h('strong', {}, '🎧 Recording transcode diagnostics'));
  toolbar.appendChild(recIdInput);
  toolbar.appendChild(refreshBtn);
  toolbar.appendChild(ffStatusBtn);
  const bulkBtn = h('button', { class: 'btn primary' }, '🔁 Re-transcode all');
  bulkBtn.onclick = async () => {
    if (!confirm('Re-transcode every recording in this tenant?\nThis runs ffmpeg on each one (up to 500). Takes a few minutes.')) return;
    bulkBtn.disabled = true; bulkBtn.textContent = 'Working… (may take minutes)';
    try {
      const url = '/api/recordings/retranscode-all?token=' + encodeURIComponent(CRM.token || '');
      const resp = await fetch(url);
      const j = await resp.json();
      if (j.ok) {
        toast('Done: ' + j.done + ' converted, ' + j.skipped + ' skipped, ' + j.failed + ' failed', 'ok');
        load();
      } else { toast('Bulk re-transcode failed: ' + (j.error || resp.status), 'err'); }
    } catch (e) { toast('Bulk re-transcode error: ' + e.message, 'err'); }
    bulkBtn.disabled = false; bulkBtn.textContent = '🔁 Re-transcode all';
  };
  toolbar.appendChild(bulkBtn);
  toolbar.appendChild(h('span', { class: 'muted', style: { fontSize: '.8rem' } },
    'Every transcode attempt (upload, on-play, manual). Newest first.'));
  wrap.appendChild(toolbar);

  const ffStatus = h('div', {});
  wrap.appendChild(ffStatus);
  ffStatusBtn.onclick = async () => {
    ffStatus.innerHTML = '<div class="muted">Checking…</div>';
    try {
      const resp = await fetch('/api/recordings/ffmpeg-status');
      const j = await resp.json();
      const ok = !!j.ok;
      ffStatus.innerHTML = '';
      ffStatus.appendChild(h('div', { class: 'card', style: { background: ok ? '#dcfce7' : '#fee2e2', color: ok ? '#166534' : '#991b1b', padding: '.6rem .9rem', borderRadius: '6px', margin: '.5rem 0' } },
        h('div', {}, (ok ? '✅' : '❌') + ' ffmpeg ' + (ok ? 'is working' : 'NOT available')),
        h('div', { style: { fontSize: '.78rem', marginTop: '.3rem' } }, 'binary: ' + (j.binary || '(none)')),
        h('div', { style: { fontSize: '.78rem' } }, 'version: ' + (j.version || '(unknown)'))
      ));
    } catch (e) {
      ffStatus.innerHTML = '<div class="error-box">' + esc(e.message) + '</div>';
    }
  };

  const tableHost = h('div', {});
  wrap.appendChild(tableHost);

  async function load() {
    tableHost.innerHTML = '<div class="loading">Loading…</div>';
    let res;
    try {
      const opts = {};
      if (recIdInput.value) opts.recording_id = Number(recIdInput.value);
      opts.limit = 200;
      res = await api('api_admin_recordingDiag_list', opts);
    } catch (e) {
      tableHost.innerHTML = '<div class="error-box">' + esc(e.message) + '</div>';
      return;
    }
    const rows = (res && res.rows) || [];
    if (!rows.length) {
      tableHost.innerHTML = '';
      tableHost.appendChild(h('div', { class: 'card muted' },
        (res && res.note) || 'No diagnostics yet — play any recording to generate one.'));
      return;
    }
    const tbl = h('table', { class: 'tbl' });
    tbl.appendChild(h('thead', {}, h('tr', {},
      h('th', {}, 'When'),
      h('th', {}, 'Rec #'),
      h('th', {}, 'Action'),
      h('th', {}, 'Result'),
      h('th', {}, 'In'),
      h('th', {}, 'Out'),
      h('th', {}, 'Duration'),
      h('th', {}, 'ffmpeg'),
      h('th', {}, 'Error')
    )));
    const body = h('tbody', {});
    rows.forEach(r => {
      const ok = r.result === 'ok';
      const badge = h('span', { style: { padding: '2px 6px', borderRadius: '4px', fontWeight: 600, fontSize: '.78rem', background: ok ? '#dcfce7' : '#fee2e2', color: ok ? '#166534' : '#991b1b' } }, r.result || '?');
      body.appendChild(h('tr', {},
        h('td', { class: 'muted', style: { whiteSpace: 'nowrap' } }, fmtDate(r.created_at, 'relative')),
        h('td', {}, String(r.recording_id || '–')),
        h('td', {}, h('code', { style: { fontSize: '.78rem' } }, r.action || '')),
        h('td', {}, badge),
        h('td', { class: 'muted' }, r.bytes_in != null ? Math.round(r.bytes_in / 1024) + ' KB' : ''),
        h('td', { class: 'muted' }, r.bytes_out != null ? Math.round(r.bytes_out / 1024) + ' KB' : ''),
        h('td', { class: 'muted' }, r.duration_ms != null ? r.duration_ms + ' ms' : ''),
        h('td', { class: 'muted', style: { fontSize: '.74rem', maxWidth: '180px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }, title: (r.ffmpeg_binary || '') + ' — ' + (r.ffmpeg_version || '') }, r.ffmpeg_binary ? r.ffmpeg_binary.split('/').pop() : '(none)'),
        h('td', { class: 'muted', style: { fontSize: '.74rem', maxWidth: '320px', color: '#991b1b' } }, r.error_message || '')
      ));
    });
    tbl.appendChild(body);
    tableHost.innerHTML = '';
    tableHost.appendChild(tbl);
  }

  refreshBtn.onclick = load;
  recIdInput.onkeydown = (e) => { if (e.key === 'Enter') load(); };
  load();
  return wrap;
}

async function adminWebhookLogs() {
  const wrap = h('div', { class: 'admin-section' });
  wrap.appendChild(h('h4', {}, '📡 Webhook logs'));
  wrap.appendChild(h('p', { class: 'muted' },
    'Every external POST/GET on /hook/* (website forms, Pabbly, Make.com, Meta, lead-source vendors) is captured here. Click any row to view the full payload + the response we sent back. Useful for verifying field mappings or chasing "the website said it sent the lead but it never arrived" tickets. Keeps the most recent 2000 events; older rows auto-prune.'));

  // Toolbar — path filter + refresh
  const pathFilter = h('input', { type: 'search', placeholder: 'Filter by path (e.g. /hook/website)', style: { minWidth: '260px' } });
  const refreshBtn = h('button', { class: 'btn primary sm' }, '🔄 Refresh');
  // Backfill button — see comment in stockbox patch.
  const backfillBtn = h('button', { class: 'btn sm',
    title: 'Re-apply the new source resolver to leads created in the last 30 days. Only updates leads whose current source is a generic default (Website/manual/empty).',
    onclick: async () => {
      backfillBtn.disabled = true;
      backfillBtn.textContent = 'Scanning\u2026';
      try {
        const dry = await api('api_admin_webhookLogs_backfillSources', { daysBack: 30, dryRun: true });
        if (!dry || dry.proposed === 0) {
          alert('No leads need updating in the last 30 days. ' + (dry ? '(' + dry.logs_scanned + ' logs scanned)' : ''));
          return;
        }
        const sampleTxt = (dry.sample || []).slice(0, 10).map(s =>
          '\u2022 ' + (s.name || s.phone) + '  \u2192  source: "' + (s.old || '\u2014') + '"  \u21D2  "' + s.new + '"'
        ).join('\n');
        const ok = confirm(
          'Found ' + dry.proposed + ' lead(s) to update (scanned ' + dry.logs_scanned + ' webhook logs).\n\n' +
          'Sample:\n' + sampleTxt + '\n\nProceed with the update?'
        );
        if (!ok) return;
        backfillBtn.textContent = 'Updating\u2026';
        const live = await api('api_admin_webhookLogs_backfillSources', { daysBack: 30, dryRun: false });
        alert('\u2705 Updated ' + live.leads_updated + ' lead(s).');
      } catch (e) {
        alert('Backfill failed: ' + e.message);
      } finally {
        backfillBtn.disabled = false;
        backfillBtn.textContent = '\uD83D\uDD01 Backfill source from logs';
      }
    }
  }, '\uD83D\uDD01 Backfill source from logs');
  const status = h('span', { class: 'muted', style: { marginLeft: '.6rem' } }, '');
  wrap.appendChild(h('div', { class: 'toolbar', style: { marginBottom: '.6rem' } },
    pathFilter, refreshBtn, backfillBtn, status
  ));

  const tableHost = h('div', {});
  wrap.appendChild(tableHost);

  async function load() {
    status.textContent = 'Loading…';
    tableHost.innerHTML = '';
    let resp;
    try { resp = await api('api_admin_webhookLogs_list', { path: pathFilter.value || undefined, limit: 200 }); }
    catch (e) { status.textContent = ''; tableHost.appendChild(h('div', { class: 'error-box' }, e.message)); return; }
    const rows = (resp && resp.rows) || [];
    status.textContent = rows.length + ' event' + (rows.length === 1 ? '' : 's');
    if (!rows.length) {
      tableHost.appendChild(h('p', { class: 'muted', style: { padding: '1rem' } },
        (resp && resp.note) || 'No webhook events yet. Once an inbound hit lands on /hook/* it will show up here.'));
      return;
    }
    const tbl = h('table', { class: 'mini-table' },
      h('thead', {}, h('tr', {},
        h('th', {}, 'When'),
        h('th', {}, 'Method'),
        h('th', {}, 'Path'),
        h('th', { style: { textAlign: 'right' } }, 'Status'),
        h('th', { style: { textAlign: 'right' } }, 'Duration'),
        h('th', {}, 'Source IP'),
        h('th', {}, 'Body preview')
      )),
      h('tbody', {}, ...rows.map(r => {
        const tr = h('tr', { style: { cursor: 'pointer' } });
        tr.appendChild(h('td', { class: 'muted', style: { fontSize: '.8rem', whiteSpace: 'nowrap' } },
          new Date(r.created_at).toLocaleString()));
        tr.appendChild(h('td', {}, h('code', {}, r.method)));
        tr.appendChild(h('td', { style: { fontFamily: 'ui-monospace, monospace', fontSize: '.8rem' } }, r.path));
        const okBadge = r.response_code >= 200 && r.response_code < 300 ? 'ok' : (r.response_code >= 400 ? 'err' : 'warn');
        tr.appendChild(h('td', { style: { textAlign: 'right' } }, h('span', { class: 'badge ' + okBadge }, String(r.response_code || '?'))));
        tr.appendChild(h('td', { class: 'muted', style: { textAlign: 'right', fontSize: '.8rem' } }, (r.duration_ms || 0) + ' ms'));
        tr.appendChild(h('td', { class: 'muted', style: { fontSize: '.78rem' } }, r.source_ip || '—'));
        tr.appendChild(h('td', { style: { maxWidth: '320px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontFamily: 'ui-monospace, monospace', fontSize: '.78rem', color: '#475569' } },
          (r.body_preview || '').slice(0, 180)));
        tr.onclick = () => _openWebhookLogDetails(r);
        return tr;
      }))
    );
    tableHost.appendChild(h('div', { class: 'table-wrap' }, tbl));
  }

  refreshBtn.onclick = load;
  pathFilter.addEventListener('change', load);
  pathFilter.addEventListener('keydown', ev => { if (ev.key === 'Enter') load(); });
  load();

  return wrap;
}

function _openWebhookLogDetails(row) {
  // Use the same modal-backdrop / modal pattern used everywhere else on
  // this app (confirmDialog, recording details, bot flow modals etc.).
  // Earlier this used a non-existent .modal-overlay class, which made the
  // detail view invisible. Click on the dark backdrop closes the modal.
  const backdrop = h('div', { class: 'modal-backdrop', onclick: (ev) => { if (ev.target === backdrop) backdrop.remove(); } });
  const modal = h('div', { class: 'modal modal-lg' });
  const closeBtn = h('button', { class: 'btn sm', onclick: () => backdrop.remove() }, '\u2715');
  modal.appendChild(h('div', { class: 'modal-head' },
    h('h3', {}, '\uD83D\uDCE1 ' + (row.method || '') + ' ' + (row.path || '')),
    closeBtn
  ));
  modal.appendChild(h('div', { class: 'muted', style: { fontSize: '.82rem', marginBottom: '.5rem' } },
    fmtDate(row.created_at) + ' \u00B7 status ' + (row.response_code || '\u2013') + ' \u00B7 ' + (row.duration_ms || 0) + ' ms \u00B7 from ' + (row.source_ip || 'unknown')));
  const loadingDiv = h('div', { class: 'loading' }, 'Loading\u2026');
  modal.appendChild(loadingDiv);
  backdrop.appendChild(modal);
  document.body.appendChild(backdrop);

  api('api_admin_webhookLogs_get', row.id).then(full => {
    if (!full) { loadingDiv.textContent = 'Not found'; return; }
    loadingDiv.remove();
    const section = (title, content) => {
      const wrap = h('div', { style: { marginTop: '1rem' } });
      const head = h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
        h('b', {}, title),
        h('button', { class: 'btn sm', onclick: () => { navigator.clipboard.writeText(content || ''); toast('Copied'); } }, 'Copy')
      );
      const pre = h('pre', { style: { background: '#0f172a', color: '#e2e8f0', padding: '.7rem', borderRadius: '6px', overflow: 'auto', maxHeight: '300px', fontSize: '.78rem', whiteSpace: 'pre-wrap', wordBreak: 'break-all' } }, content || '(empty)');
      wrap.appendChild(head);
      wrap.appendChild(pre);
      return wrap;
    };
    const tryPretty = (txt) => {
      if (!txt) return '';
      try { return JSON.stringify(JSON.parse(txt), null, 2); } catch (_) { return String(txt); }
    };
    modal.appendChild(section('Request body', tryPretty(full.body_text)));
    modal.appendChild(section('Response body', tryPretty(full.response_text)));
    if (full.query_json && full.query_json !== '{}') {
      modal.appendChild(section('Query params', tryPretty(full.query_json)));
    }
    modal.appendChild(section('Headers (auth redacted)', tryPretty(full.headers_json)));
    modal.appendChild(h('div', { class: 'muted', style: { marginTop: '.5rem', fontSize: '.74rem' } },
      'User-Agent: ' + (full.user_agent || '')));
  }).catch(e => { loadingDiv.textContent = 'Error: ' + e.message; });
}

