VIEWS.edustudents = async (view) => {
  view.innerHTML = '';
  view.appendChild(h('div', { style:{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'.75rem' } },
    h('h2', { style:{ margin:0 } }, '👥 Students — Fee Collection View'),
    h('div', { style:{ display:'flex', gap:'.4rem' } },
      h('button', { class:'btn', onclick: () => openManageBranchesModal() }, '🏢 Manage Branches')
    )
  ));
  view.appendChild(h('p', { class:'muted' }, 'Every enrolled student with payment status. Click a row to open the lead and update fees.'));

  // Filters
  const fSearch = h('input', { type:'text', placeholder:'Search student / course / batch…', style:{ flex:1, minWidth:'200px' } });
  const fBranch = h('select', {}, h('option', { value:'' }, '— All branches —'));
  const filterRow = h('div', { class:'card', style:{ padding:'.6rem .8rem', marginBottom:'.6rem', display:'flex', gap:'.5rem', flexWrap:'wrap', alignItems:'center' } },
    fSearch, fBranch,
    h('button', { class:'btn primary', onclick: () => render() }, 'Apply')
  );
  view.appendChild(filterRow);

  // Load branches into the filter
  try {
    const bs = await api('api_edu_branches_list');
    (bs || []).filter(b => Number(b.is_active)).forEach(b => fBranch.appendChild(h('option', { value: b.id }, b.name + (b.code ? ' (' + b.code + ')' : ''))));
  } catch (_) {}

  const body = h('div', {});
  view.appendChild(body);

  async function render() {
    body.innerHTML = '<div class="muted" style="padding:1rem">Loading…</div>';
    try {
      const r = await api('api_edu_students_list', { search: fSearch.value || null, branch_id: fBranch.value ? Number(fBranch.value) : null });
      const rows = r.students || [];
      body.innerHTML = '';

      if (!rows.length) {
        body.appendChild(h('div', { class:'muted', style:{ padding:'2rem', textAlign:'center' } }, 'No enrollments match the filter. Enroll a student from any lead modal.'));
        return;
      }

      const tbl = h('table', { class:'mini-table' },
        h('thead', {}, h('tr', {},
          h('th', {}, 'Student'),
          h('th', {}, 'Course / Batch'),
          h('th', {}, 'Branch'),
          h('th', {}, 'Billed'),
          h('th', {}, 'Collected'),
          h('th', {}, 'Outstanding'),
          h('th', {}, 'Overdue'),
          h('th', {}, 'Last paid'),
          h('th', {}, 'Status'),
          h('th', {}, '')
        )),
        h('tbody', {},
          ...rows.map(s => h('tr', { style: Number(s.overdue) > 0 ? { background:'#fef2f2' } : {} },
            h('td', {},
              h('div', { style:{ fontWeight:600 } }, s.student_name || '—'),
              s.phone ? h('div', { class:'muted', style:{ fontSize:'.75em' } }, s.phone) : null
            ),
            h('td', {},
              h('div', {}, s.course_name || '—'),
              s.batch_name ? h('div', { class:'muted', style:{ fontSize:'.75em' } }, s.batch_name) : null
            ),
            h('td', {}, s.branch_name || h('span', { class:'muted' }, '—')),
            h('td', {}, '₹' + Number(s.billed).toLocaleString('en-IN')),
            h('td', { style:{ color:'#16a34a', fontWeight:600 } }, '₹' + Number(s.collected).toLocaleString('en-IN')),
            h('td', {}, '₹' + Number(s.outstanding).toLocaleString('en-IN')),
            h('td', { style:{ color: Number(s.overdue) > 0 ? '#dc2626' : '#64748b', fontWeight: Number(s.overdue) > 0 ? 600 : 400 } }, '₹' + Number(s.overdue).toLocaleString('en-IN')),
            h('td', { class:'muted', style:{ fontSize:'.85em' } }, s.last_payment_at ? String(s.last_payment_at).slice(0,10) : '—'),
            h('td', {},
              Number(s.installments_paid) + '/' + Number(s.installments_total),
              Number(s.overdue) > 0 ? h('span', { style:{ marginLeft:'.3rem', background:'#fee2e2', color:'#991b1b', padding:'1px 5px', borderRadius:'3px', fontSize:'.7em' } }, 'OVERDUE') : null
            ),
            h('td', {},
              h('button', { class:'btn sm primary', onclick: () => openLeadModal(s.lead_id) }, '💰 Collect Fee')
            )
          ))
        )
      );
      body.appendChild(tbl);
    } catch (e) {
      body.innerHTML = '';
      if (/not active/i.test(String(e.message || ''))) {
        body.appendChild(h('div', { class:'error-box' }, 'Education pack is not installed. Go to Settings → 🧩 Industry Packs to enable.'));
      } else {
        body.appendChild(h('div', { class:'error-box' }, e.message));
      }
    }
  }
  render();
};

async function openManageBranchesModal() {
  const m = h('div', { class:'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class:'modal modal-lg' });
  modal.appendChild(h('div', { class:'modal-head' },
    h('h3', {}, '🏢 Education branches'),
    h('button', { class:'btn ghost', onclick: () => m.remove() }, '✕')
  ));
  const body = h('div', { class:'modal-body' });
  modal.appendChild(body);

  const refresh = async () => {
    body.innerHTML = '<div class="muted">Loading…</div>';
    try {
      const list = await api('api_edu_branches_list');
      body.innerHTML = '';
      if (!list.length) body.appendChild(h('div', { class:'muted', style:{ padding:'.5rem 0' } }, 'No branches yet — add your first one below.'));
      list.forEach(b => {
        body.appendChild(h('div', { class:'card', style:{ padding:'.5rem .7rem', marginBottom:'.4rem', display:'flex', justifyContent:'space-between', alignItems:'center' } },
          h('div', {},
            h('strong', {}, b.name + (b.code ? ' · ' + b.code : '')),
            b.address ? h('div', { class:'muted', style:{ fontSize:'.78em' } }, '📍 ' + b.address) : null,
            b.phone   ? h('div', { class:'muted', style:{ fontSize:'.78em' } }, '📞 ' + b.phone) : null
          ),
          h('div', { style:{ display:'flex', gap:'.3rem' } },
            h('button', { class:'btn sm', onclick: () => editBranch(b) }, 'Edit'),
            Number(b.is_active)
              ? h('button', { class:'btn sm', onclick: async () => { await api('api_edu_branches_save', Object.assign({}, b, { is_active: 0 })); refresh(); } }, 'Disable')
              : h('button', { class:'btn sm primary', onclick: async () => { await api('api_edu_branches_save', Object.assign({}, b, { is_active: 1 })); refresh(); } }, 'Enable')
          )
        ));
      });

      const fName = h('input', { type:'text', placeholder:'Branch name (e.g. Andheri West)' });
      const fCode = h('input', { type:'text', placeholder:'Short code (e.g. AND)' });
      const fAddr = h('input', { type:'text', placeholder:'Address' });
      const fPhone = h('input', { type:'text', placeholder:'Phone' });
      body.appendChild(h('div', { style:{ marginTop:'.7rem', paddingTop:'.7rem', borderTop:'1px solid #e5e7eb' } },
        h('h4', { style:{ margin:'0 0 .4rem' } }, '+ Add new branch'),
        h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'.4rem' } }, fName, fCode, fAddr, fPhone),
        h('button', { class:'btn primary', style:{ marginTop:'.4rem' }, onclick: async () => {
          if (!fName.value.trim()) { toast('Branch name required', 'err'); return; }
          try {
            await api('api_edu_branches_save', { name: fName.value.trim(), code: fCode.value, address: fAddr.value, phone: fPhone.value });
            toast('Branch added');
            refresh();
          } catch (e) { toast(e.message, 'err'); }
        } }, '+ Save branch')
      ));
    } catch (e) { body.innerHTML = ''; body.appendChild(h('div', { class:'error-box' }, e.message)); }
  };

  function editBranch(b) {
    const fName = h('input', { type:'text', value: b.name });
    const fCode = h('input', { type:'text', value: b.code || '' });
    const fAddr = h('input', { type:'text', value: b.address || '' });
    const fPhone = h('input', { type:'text', value: b.phone || '' });
    const m2 = h('div', { class:'modal-backdrop' });
    const card = h('div', { class:'modal' });
    card.appendChild(h('div', { class:'modal-head' }, h('h3', {}, 'Edit branch'), h('button', { class:'btn ghost', onclick: () => m2.remove() }, '✕')));
    card.appendChild(h('div', { class:'modal-body' },
      h('label', {}, 'Name', fName),
      h('label', {}, 'Code', fCode),
      h('label', {}, 'Address', fAddr),
      h('label', {}, 'Phone', fPhone)
    ));
    card.appendChild(h('div', { class:'actions' },
      h('button', { class:'btn', onclick: () => m2.remove() }, 'Cancel'),
      h('button', { class:'btn primary', onclick: async () => {
        try {
          await api('api_edu_branches_save', { id: b.id, name: fName.value.trim(), code: fCode.value, address: fAddr.value, phone: fPhone.value });
          toast('Saved');
          m2.remove();
          refresh();
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Save')
    ));
    m2.appendChild(card);
    document.body.appendChild(m2);
  }

  m.appendChild(modal);
  document.body.appendChild(m);
  refresh();
}

// ───── Student document upload on Education lead-modal panel ─────
// We monkey-patch openLeadModal so that AFTER the modal renders we append
// a "📎 Student documents" block to the existing 🎓 Fees section when
// Education pack is active.
(function _wireEduDocsPanel() {
  if (typeof openLeadModal !== 'function') return;
  const _orig = openLeadModal;
  window.openLeadModal = async function patchedOpenLeadModalForEduDocs(id) {
    const out = await _orig.apply(this, arguments);
    if (!id) return out;
    setTimeout(async () => {
      try {
        // Only proceed if Education is active for this tenant
        const installed = await api('api_packs_listInstalled').catch(() => []);
        const eduActive = (installed || []).some(p => p.pack_id === 'education' && Number(p.is_active));
        if (!eduActive) return;
        const r = await api('api_edu_enrollment_byLead', id);
        const enrolls = r || [];
        if (!enrolls.length) return;
        const body = document.querySelector('.modal-backdrop:last-of-type .modal');
        if (!body || body.querySelector('.edu-docs-block')) return;

        const wrap = h('div', { class:'pack-block edu-docs-block', style:{ marginTop:'1rem', borderTop:'1px solid #e5e7eb', paddingTop:'1rem' } },
          h('h4', { style:{ margin:'0 0 .5rem' } }, '📎 Student documents')
        );

        for (const e of enrolls) {
          const enrId = e.id || e.enrollment_id;
          if (!enrId) continue;
          const sub = h('div', { style:{ marginBottom:'.6rem', padding:'.5rem .7rem', background:'#f8fafc', borderRadius:'6px' } });
          sub.appendChild(h('div', { style:{ fontWeight:600, fontSize:'.9em' } },
            (e.course_name || 'Enrollment') + (e.batch_name ? ' · ' + e.batch_name : '')));
          const listEl = h('div', {});
          sub.appendChild(listEl);

          // Upload row
          const fType = h('select', {},
            ...['Aadhar','Photo','Marksheet 10th','Marksheet 12th','PAN','Address Proof','Agreement','Other']
              .map(t => h('option', { value: t.toLowerCase().replace(/\s+/g,'_') }, t))
          );
          const fLabel = h('input', { type:'text', placeholder:'Label (optional)', style:{ flex:1 } });
          const fFile = h('input', { type:'file', accept:'image/*,application/pdf' });
          sub.appendChild(h('div', { style:{ marginTop:'.4rem', display:'flex', gap:'.3rem', flexWrap:'wrap', alignItems:'center' } },
            fType, fLabel, fFile,
            h('button', { class:'btn sm primary', onclick: async () => {
              if (!fFile.files[0]) { toast('Pick a file', 'err'); return; }
              const file = fFile.files[0];
              try {
                // Try existing tenant upload endpoint /api/files/upload
                const fd = new FormData();
                fd.append('file', file);
                let storageUrl = '';
                try {
                  const up = await fetch('/api/files/upload', { method:'POST', headers: { 'Authorization': 'Bearer ' + (CRM.token || '') }, body: fd });
                  if (up.ok) {
                    const j = await up.json();
                    storageUrl = j.url || j.path || j.location || '';
                  }
                } catch (_) {}
                // Fallback: data URL for very small files
                if (!storageUrl && file.size < 200000) {
                  storageUrl = await new Promise(res => { const r = new FileReader(); r.onload = () => res(r.result); r.readAsDataURL(file); });
                }
                if (!storageUrl) { toast('File upload not available — please configure file storage', 'err'); return; }
                await api('api_edu_documents_register', {
                  enrollment_id: enrId,
                  doc_type: fType.value,
                  label: fLabel.value || file.name,
                  filename: file.name,
                  mime_type: file.type,
                  file_size: file.size,
                  storage_url: storageUrl
                });
                toast('Document uploaded');
                refreshDocs();
              } catch (err) { toast(err.message, 'err'); }
            } }, '📤 Upload')
          ));

          async function refreshDocs() {
            try {
              const docs = await api('api_edu_documents_byEnrollment', enrId);
              listEl.innerHTML = '';
              if (!docs.length) { listEl.appendChild(h('div', { class:'muted', style:{ fontSize:'.8em', padding:'.3rem 0' } }, 'No documents yet.')); return; }
              docs.forEach(d => {
                listEl.appendChild(h('div', { style:{ display:'flex', alignItems:'center', gap:'.4rem', padding:'.25rem 0', fontSize:'.85em', borderBottom:'1px dashed #e5e7eb' } },
                  h('span', { style:{ background:'#e0e7ff', color:'#3730a3', padding:'1px 6px', borderRadius:'3px', fontSize:'.75em' } }, (d.doc_type || 'other').toUpperCase()),
                  d.storage_url ? h('a', { href: d.storage_url, target:'_blank', style:{ flex:1 } }, d.label || d.filename) : h('span', { style:{ flex:1 } }, d.label || d.filename),
                  Number(d.is_verified)
                    ? h('span', { style:{ color:'#16a34a' }, title:'Verified' }, '✓')
                    : h('button', { class:'btn xs', onclick: async () => { await api('api_edu_documents_verify', { id: d.id, is_verified: 1 }); refreshDocs(); } }, 'Verify'),
                  h('button', { class:'btn xs danger', onclick: async () => { if (confirm('Delete this document?')) { await api('api_edu_documents_delete', d.id); refreshDocs(); } } }, '🗑')
                ));
              });
            } catch (_) {}
          }
          refreshDocs();
          wrap.appendChild(sub);
        }

        // Append after existing fees block if any
        const feesBlock = body.querySelector('.fees-block') || body.querySelector('.pack-block');
        if (feesBlock && feesBlock.parentNode) feesBlock.parentNode.insertBefore(wrap, feesBlock.nextSibling);
        else {
          const actions = body.querySelector('.actions');
          if (actions) body.insertBefore(wrap, actions); else body.appendChild(wrap);
        }
      } catch (_) {}
    }, 300);
    return out;
  };
})();

try {
  window.openManageBranchesModal = openManageBranchesModal;
} catch (_) {}


// ═════════════════════════════════════════════════════════════════════
// 🎓 Education pack — Phase 4 (Course terminology, sale-closure modal)
// ═════════════════════════════════════════════════════════════════════
// Pack-aware terminology swap: when Education is installed, references to
// "Product" become "Course" in the sidebar nav label + Products page heading.
// The underlying tenant `products` table is untouched — pure label swap so
// Generic CRM features are not affected.
(function _eduTerminologySwap() {
  function apply() {
    try {
      const installed = (CRM.installedPacks instanceof Set) ? CRM.installedPacks : null;
      const isEdu = installed && installed.has('education');
      if (!isEdu) return;

      // Sidebar nav link
      document.querySelectorAll('.sidebar nav a, #bottom-nav a').forEach(a => {
        if (a.getAttribute('href') === '#/products' || a.dataset.view === 'products') {
          const label = a.querySelector('span:not(.nav-icon):not(.bn-ico)');
          if (label && /Products?/.test(label.textContent)) label.textContent = 'Courses';
          const ico = a.querySelector('.nav-icon, .bn-ico');
          if (ico) ico.textContent = '📚';
        }
      });

      // Settings subtab + page heading: catch any text node containing
      // "📦 Products" and swap.
      document.querySelectorAll('.subtab, .admin-settings-item, h2, h3').forEach(el => {
        if (/^\s*📦\s*Products?\s*$/.test(el.textContent)) {
          el.textContent = '📚 Courses';
        }
      });
    } catch (_) {}
  }
  // Apply on first render + every hash change (covers re-renders)
  document.addEventListener('DOMContentLoaded', apply);
  window.addEventListener('hashchange', () => setTimeout(apply, 50));
  // Periodic re-check for late renders (e.g. settings tabs)
  setInterval(apply, 1500);
})();

// ───── Sale-closure modal — Token + custom installments ─────
async function openCloseSaleModal(leadId, onDone) {
  const m = h('div', { class:'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class:'modal modal-lg' });
  modal.appendChild(h('div', { class:'modal-head' },
    h('h3', {}, '💰 Close Sale — Enroll student & set payment schedule'),
    h('button', { class:'btn ghost', onclick: () => m.remove() }, '✕')
  ));

  const body = h('div', { class:'modal-body' });

  // Course + batch + branch
  const fCourse = h('input', { type:'text', placeholder:'e.g. JEE Advanced 2027' });
  const fBatch  = h('input', { type:'text', placeholder:'e.g. Morning · 8 AM' });
  const fBranch = h('select', {}, h('option', { value:'' }, '— No specific branch —'));

  body.appendChild(h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'.6rem' } },
    h('label', {}, 'Course name', fCourse),
    h('label', {}, 'Batch', fBatch),
    h('label', { style:{ gridColumn:'span 2' } }, 'Branch (optional)', fBranch)
  ));

  // Token row
  body.appendChild(h('h4', { style:{ margin:'1rem 0 .3rem 0', color:'#0c4a6e' } }, '🪙 Token amount (paid at sale closure)'));
  const fTokenAmt    = h('input', { type:'number', placeholder:'5000', style:{ width:'100%' } });
  const fTokenDate   = h('input', { type:'date',  value: new Date().toISOString().slice(0,10) });
  const fTokenMethod = h('select', {}, ...['upi','cash','bank','card','cheque'].map(m => h('option', { value:m }, m.toUpperCase())));
  const fTokenRef    = h('input', { type:'text', placeholder:'Receipt / txn id' });
  const fTokenPaid   = h('input', { type:'checkbox', checked:'checked' });
  body.appendChild(h('div', { class:'card', style:{ padding:'.6rem .8rem', background:'#f0f9ff' } },
    h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:'.4rem' } },
      h('label', {}, 'Amount ₹', fTokenAmt),
      h('label', {}, 'Due / received on', fTokenDate),
      h('label', {}, 'Method', fTokenMethod),
      h('label', {}, 'Reference', fTokenRef)
    ),
    h('label', { style:{ display:'flex', gap:'.4rem', marginTop:'.3rem', fontSize:'.85em' } }, fTokenPaid, h('span', {}, 'Token already received (record as PAID)'))
  ));

  // Installments — start with 3 rows, add/remove
  body.appendChild(h('h4', { style:{ margin:'1rem 0 .3rem 0', color:'#0c4a6e' } }, '📅 Installment schedule (after token)'));
  const insWrap = h('div', {});
  body.appendChild(insWrap);

  function addInsRow(prefill) {
    const idx = insWrap.children.length + 1;
    const fLabel = h('input', { type:'text', value: (prefill && prefill.label) || ('Installment ' + idx), style:{ flex:1 } });
    const fAmt   = h('input', { type:'number', placeholder:'Amount ₹', value: (prefill && prefill.amount) || '', style:{ width:'120px' } });
    const fDate  = h('input', { type:'date',   value: (prefill && prefill.due_date) || '' });
    const row = h('div', { class:'card', style:{ padding:'.4rem .6rem', marginBottom:'.3rem', display:'flex', gap:'.3rem', alignItems:'center' } },
      h('span', { class:'muted', style:{ minWidth:'24px' } }, '#' + idx),
      fLabel, fAmt, fDate,
      h('button', { class:'btn xs danger', onclick: () => { row.remove(); _renumber(); } }, '✕')
    );
    row._getRow = () => ({
      label: fLabel.value, amount: Number(fAmt.value || 0), due_date: fDate.value
    });
    insWrap.appendChild(row);
  }
  function _renumber() {
    [...insWrap.children].forEach((row, i) => {
      const s = row.querySelector('span.muted');
      if (s) s.textContent = '#' + (i+1);
    });
  }

  body.appendChild(h('div', { style:{ display:'flex', gap:'.3rem', marginTop:'.3rem' } },
    h('button', { class:'btn sm', onclick: () => addInsRow() }, '+ Add installment'),
    h('button', { class:'btn sm', onclick: () => { insWrap.innerHTML=''; ['1','2','3'].forEach(()=>addInsRow()); } }, '↺ Reset to 3 rows'),
    h('button', { class:'btn sm', onclick: () => {
      // Quick fill: split remainder of (annual fee guess) into equal monthly payments
      const guess = Number(prompt('Total annual fee (₹) to split — token will be deducted:', '60000') || 0);
      if (!guess) return;
      const months = Number(prompt('Number of monthly installments:', '6') || 0);
      if (!months) return;
      const tok = Number(fTokenAmt.value || 0);
      const rem = guess - tok;
      const per = Math.round((rem / months) * 100) / 100;
      const startDate = fTokenDate.value || new Date().toISOString().slice(0,10);
      insWrap.innerHTML = '';
      for (let i = 0; i < months; i++) {
        const d = new Date(startDate); d.setMonth(d.getMonth() + (i+1));
        addInsRow({ label: 'Installment ' + (i+1), amount: per, due_date: d.toISOString().slice(0,10) });
      }
    } }, '⚡ Quick split')
  ));

  // Init 3 rows
  ['1','2','3'].forEach(()=>addInsRow());

  // Live total
  const totalEl = h('div', { style:{ marginTop:'.8rem', padding:'.6rem', background:'#fef3c7', borderRadius:'6px', fontWeight:600 } }, 'Total: ₹0');
  body.appendChild(totalEl);
  function _recalc() {
    const tok = Number(fTokenAmt.value || 0);
    const ins = [...insWrap.children].reduce((s, row) => s + (row._getRow ? Number(row._getRow().amount || 0) : 0), 0);
    totalEl.textContent = 'Total: ₹' + (tok + ins).toLocaleString('en-IN') + ' (Token ₹' + tok.toLocaleString('en-IN') + ' + Installments ₹' + ins.toLocaleString('en-IN') + ')';
  }
  body.addEventListener('input', _recalc);
  setTimeout(_recalc, 100);

  modal.appendChild(body);
  modal.appendChild(h('div', { class:'actions' },
    h('button', { class:'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class:'btn primary', onclick: async () => {
      if (!Number(fTokenAmt.value)) { toast('Token amount required', 'err'); return; }
      const installments = [...insWrap.children]
        .map(row => row._getRow && row._getRow())
        .filter(r => r && r.amount > 0 && r.due_date);
      try {
        const r = await api('api_edu_enrollment_createCustom', {
          lead_id: leadId,
          course_name: fCourse.value || '',
          batch_name: fBatch.value || '',
          branch_id: fBranch.value ? Number(fBranch.value) : null,
          token_amount: Number(fTokenAmt.value),
          token_due_date: fTokenDate.value,
          token_paid: fTokenPaid.checked ? 1 : 0,
          token_method: fTokenMethod.value,
          token_reference: fTokenRef.value || '',
          installments
        });
        toast('✓ Sale closed · ₹' + Number(r.total_amount).toLocaleString('en-IN') + ' total, ' + r.installments_added + ' installments');
        m.remove();
        if (onDone) onDone();
      } catch (e) { toast(e.message, 'err'); }
    } }, '💰 Close Sale')
  ));

  m.appendChild(modal);
  document.body.appendChild(m);

  // Populate branches
  try {
    const bs = await api('api_edu_branches_list');
    (bs || []).filter(b => Number(b.is_active)).forEach(b => fBranch.appendChild(h('option', { value: b.id }, b.name + (b.code ? ' (' + b.code + ')' : ''))));
  } catch (_) {}
}

// Mount a "💰 Close Sale" button at the TOP of the lead modal when Education
// pack is installed (and only when the lead is NOT yet enrolled).
(function _wireEduCloseSaleButton() {
  if (typeof openLeadModal !== 'function') return;
  const _prev = openLeadModal;
  window.openLeadModal = async function patchedForCloseSale(id) {
    const out = await _prev.apply(this, arguments);
    if (!id) return out;
    setTimeout(async () => {
      try {
        const installed = await api('api_packs_listInstalled').catch(() => []);
        const eduActive = (installed || []).some(p => p.pack_id === 'education' && Number(p.is_active));
        if (!eduActive) return;
        const body = document.querySelector('.modal-backdrop:last-of-type .modal');
        if (!body || body.querySelector('.edu-close-sale-btn')) return;

        // Skip if already enrolled
        let enrolled = false;
        try {
          const e = await api('api_edu_enrollment_byLead', id);
          enrolled = Array.isArray(e) && e.length > 0;
        } catch (_) {}

        const btn = h('button', {
          class: 'btn primary edu-close-sale-btn',
          style: { background: '#16a34a', borderColor: '#16a34a', marginLeft: '.4rem' },
          onclick: () => openCloseSaleModal(id, () => { try { _prev(id); } catch (_) {} })
        }, enrolled ? '💰 Add another enrollment' : '💰 Close Sale');

        // Drop it next to the head's existing buttons / X close
        const head = body.querySelector('.modal-head');
        if (head) head.insertBefore(btn, head.lastChild);
        else body.insertBefore(btn, body.firstChild);
      } catch (_) {}
    }, 250);
    return out;
  };
})();

try { window.openCloseSaleModal = openCloseSaleModal; } catch (_) {}


// ═════════════════════════════════════════════════════════════════════
// 🎓 Education pack — Phase 4b (Stronger terminology + Course fields on Products)
// ═════════════════════════════════════════════════════════════════════
// Comprehensive "Product → Course" relabel across the SPA so coaching
// tenants see consistent terminology. The underlying `products` table is
// untouched — pure label swap.
(function _eduTerminologyV2() {
  function isEdu() {
    return (CRM.installedPacks instanceof Set) && CRM.installedPacks.has('education');
  }
  function swap() {
    if (!isEdu()) return;
    try {
      // 1) Sidebar + bottom-nav
      document.querySelectorAll('.sidebar nav a, #bottom-nav a').forEach(a => {
        if (a.getAttribute('href') === '#/products' || a.dataset.view === 'products') {
          const label = a.querySelector('span:not(.nav-icon):not(.bn-ico)');
          if (label && /Products?/i.test(label.textContent)) label.textContent = 'Courses';
          const ico = a.querySelector('.nav-icon, .bn-ico');
          if (ico && ico.textContent === '📦') ico.textContent = '📚';
        }
      });

      // 2) Settings tab + page heading swap
      document.querySelectorAll('.subtab, .admin-settings-item, h2, h3, h4, h5').forEach(el => {
        const t = (el.textContent || '').trim();
        if (/^📦\s*Products?$/i.test(t))            el.textContent = '📚 Courses';
        else if (/^Products?$/i.test(t))            el.textContent = 'Courses';
        else if (/^\+\s*Add new product$/i.test(t)) el.textContent = '+ Add new course';
      });

      // 3) Form placeholders + button labels inside the Products admin
      document.querySelectorAll('input[placeholder]').forEach(inp => {
        const ph = inp.placeholder;
        if (/Product name/i.test(ph)) inp.placeholder = ph.replace(/Product name/i, 'Course name');
        if (/^Product/i.test(inp.name || '')) {} // no-op, just in case
      });
      document.querySelectorAll('button').forEach(b => {
        const t = (b.textContent || '').trim();
        if (t === '+ Add product')      b.textContent = '+ Add course';
        if (t === 'Add product')        b.textContent = 'Add course';
      });

      // 4) Table headers "Name" / "Description" / "Price" — only inside the
      //    Products admin card (recognised by header text earlier)
      const productsCard = [...document.querySelectorAll('.card')].find(c => /Manage the products/i.test(c.textContent || ''));
      if (productsCard) {
        productsCard.querySelectorAll('p.muted').forEach(p => {
          if (/products\s*\/\s*services/i.test(p.textContent)) {
            p.textContent = 'Manage the courses your institute sells. Each course appears in the Course dropdown on the lead form, and rolls up in enrolment + revenue reports. Edit any cell and click 💾 Save to update.';
          }
        });
      }

      // 5) Lead form: "Product" label → "Course"
      document.querySelectorAll('label, span').forEach(el => {
        if (el.children.length) return;
        const t = (el.textContent || '').trim();
        if (t === 'Product')   el.textContent = 'Course';
        if (t === '📦 Product') el.textContent = '📚 Course';
      });
    } catch (_) {}
  }
  document.addEventListener('DOMContentLoaded', swap);
  window.addEventListener('hashchange', () => setTimeout(swap, 80));
  // Periodic re-check for late renders (settings tabs, modal openings)
  setInterval(swap, 1200);
})();

// ───── Course-extra fields (token + installment count + EMI amount)
// stored on each product via extra_json on the product row. Surfaces
// in the Products/Courses admin form when Education is installed.
(function _wireCourseExtrasOnProductsForm() {
  if (typeof adminProducts !== 'function') return;
  const _orig = adminProducts;
  window.adminProducts = async function patchedAdminProducts() {
    const card = await _orig.apply(this, arguments);
    try {
      const installed = (CRM.installedPacks instanceof Set) ? CRM.installedPacks : new Set();
      if (!installed.has('education')) return card;

      // Append a Course-extras helper card right under the Products table.
      const helper = h('div', { class:'card', style:{ background:'#fef9c3', borderLeft:'4px solid #f59e0b', padding:'.75rem 1rem', marginTop:'.8rem' } },
        h('h5', { style:{ margin:'0 0 .3rem' } }, '🎓 Course EMI defaults'),
        h('p', { class:'muted', style:{ margin:'0 0 .4rem', fontSize:'.85em' } },
          'Set default fee structure per course so counsellors don\'t have to re-type the same numbers at every sale closure. These values pre-fill the 💰 Close Sale dialog when the rep picks a course.'),
        h('div', { class:'muted', style:{ fontSize:'.82em' } },
          'For each course in the table above, also set its default Token, Installment amount and # of installments below.')
      );

      // Pull existing course-extras settings
      let extras = {};
      try {
        const raw = await api('api_admin_getConfig', 'edu_course_extras');
        extras = raw && raw.value ? JSON.parse(raw.value) : {};
      } catch (_) { extras = {}; }

      const courses = await api('api_products_list').catch(() => []);
      const extrasTbl = h('table', { class:'mini-table' },
        h('thead', {}, h('tr', {},
          h('th', {}, 'Course'),
          h('th', { style:{ width:'130px', textAlign:'right' } }, 'Default Token ₹'),
          h('th', { style:{ width:'150px', textAlign:'right' } }, 'EMI / installment ₹'),
          h('th', { style:{ width:'80px',  textAlign:'right' } }, '# Installments'),
          h('th', { style:{ width:'70px' } }, '')
        )),
        h('tbody', {},
          ...(courses.length === 0
            ? [h('tr', {}, h('td', { colspan: 5, class:'muted', style:{ textAlign:'center', padding:'.8rem' } }, 'Add courses above first, then come back to set EMI defaults.'))]
            : courses.map(c => {
                const ex = extras[String(c.id)] || {};
                const fTok = h('input', { type:'number', value: ex.token || '', style:{ width:'100%', textAlign:'right' } });
                const fEmi = h('input', { type:'number', value: ex.emi || '', style:{ width:'100%', textAlign:'right' } });
                const fCnt = h('input', { type:'number', value: ex.count || '', style:{ width:'100%', textAlign:'right' }, min:'1' });
                return h('tr', {},
                  h('td', {}, c.name + (c.price ? h('span', { class:'muted', style:{ fontSize:'.75em', marginLeft:'.3rem' } }, '₹' + Number(c.price).toLocaleString('en-IN')) : '')),
                  h('td', {}, fTok),
                  h('td', {}, fEmi),
                  h('td', {}, fCnt),
                  h('td', {},
                    h('button', { class:'btn sm primary', onclick: async () => {
                      extras[String(c.id)] = {
                        token: Number(fTok.value) || 0,
                        emi:   Number(fEmi.value) || 0,
                        count: Number(fCnt.value) || 0
                      };
                      try {
                        await api('api_admin_setConfig', { key: 'edu_course_extras', value: JSON.stringify(extras) });
                        toast('Saved');
                      } catch (e) { toast(e.message, 'err'); }
                    } }, '💾')
                  )
                );
              })
          )
        )
      );
      helper.appendChild(extrasTbl);
      card.appendChild(helper);
    } catch (_) {}
    return card;
  };
})();

// ───── Make openCloseSaleModal pre-fill from course extras when course is picked
// Patch the existing modal so when a course is chosen, token + EMI rows auto-fill.
// We attach to the course input via input/change events when the modal opens.
(function _autoFillCloseSaleFromCourse() {
  // Hook into openCloseSaleModal by wrapping it
  if (typeof openCloseSaleModal !== 'function') return;
  const _orig = openCloseSaleModal;
  window.openCloseSaleModal = async function patchedCloseSale(leadId, onDone) {
    const out = await _orig.apply(this, arguments);
    // After modal renders, find the Course input and the Token/EMI rows
    setTimeout(async () => {
      try {
        const backdrop = document.querySelector('.modal-backdrop:last-of-type');
        if (!backdrop) return;
        const allInputs = backdrop.querySelectorAll('input');
        let fCourse = null;
        allInputs.forEach(i => { if ((i.placeholder || '').toLowerCase().includes('jee advanced')) fCourse = i; });
        if (!fCourse) return;

        // Build a course dropdown right next to it, and auto-fill from saved extras
        const courses = await api('api_products_list').catch(() => []);
        if (!courses || !courses.length) return;
        let extras = {};
        try {
          const raw = await api('api_admin_getConfig', 'edu_course_extras');
          extras = raw && raw.value ? JSON.parse(raw.value) : {};
        } catch (_) {}

        const sel = h('select', { style:{ marginLeft:'.4rem', maxWidth:'220px' } },
          h('option', { value:'' }, '— Pick saved course —'),
          ...courses.map(c => h('option', { value: c.id, 'data-name': c.name }, c.name + (c.price ? ' · ₹' + Number(c.price).toLocaleString('en-IN') : '')))
        );
        // Insert before the course input
        fCourse.parentNode.insertBefore(sel, fCourse);

        sel.addEventListener('change', () => {
          const opt = sel.selectedOptions[0];
          if (!opt || !opt.value) return;
          fCourse.value = opt.dataset.name || '';
          const ex = extras[opt.value] || {};
          // Find token amount input + installment rows
          const tokInp = [...allInputs].find(i => i.type === 'number' && i.placeholder === '5000');
          if (tokInp && ex.token) { tokInp.value = ex.token; tokInp.dispatchEvent(new Event('input', { bubbles:true })); }
          // Auto-trigger Quick split if EMI/count set
          if (ex.emi && ex.count) {
            // Find Quick split button and simulate using its values
            const insWrap = backdrop.querySelector('.modal-body > div:nth-last-of-type(2)') || backdrop.querySelector('div + div');
            // Simpler: clear existing installment rows and add new ones
            const rows = backdrop.querySelectorAll('.modal-body .card[style*="display: flex"]');
            // ...this gets complex; just toast the values so the rep enters them manually
            toast('💡 Course EMI default: ₹' + ex.emi.toLocaleString('en-IN') + ' × ' + ex.count + ' — use Quick split or fill below');
          }
        });
      } catch (_) {}
    }, 150);
    return out;
  };
})();


// ═════════════════════════════════════════════════════════════════════
// 📚 Courses view — top-level (Education pack)
// Replaces the buried Settings → Products UX with a dedicated, integrated
// page where each Course has its fee structure (Token + EMI + count) on
// the SAME row. No more separate "Fee plans" + "Course extras" tables.
// ═════════════════════════════════════════════════════════════════════
VIEWS.educourses = async (view) => {
  view.innerHTML = '';
  view.appendChild(h('div', { style:{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'.75rem' } },
    h('h2', { style:{ margin:0 } }, '📚 Courses'),
    h('button', { class:'btn primary', onclick: () => openCourseEditModal(null, () => VIEWS.educourses(view)) }, '+ Add new course')
  ));
  view.appendChild(h('p', { class:'muted' },
    'Each course has its own fee structure (token + installment amount + count). When the rep clicks 💰 Close Sale on a lead, picking a course here auto-fills the whole payment schedule.'));

  // Pull courses + saved EMI defaults
  let courses = [];
  let extras = {};
  try {
    courses = await api('api_products_list');
    const raw = await api('api_admin_getConfig', 'edu_course_extras').catch(() => null);
    extras = (raw && raw.value) ? JSON.parse(raw.value) : {};
  } catch (e) {
    view.appendChild(h('div', { class:'error-box' }, e.message));
    return;
  }

  if (!courses.length) {
    view.appendChild(h('div', { class:'card', style:{ padding:'2rem', textAlign:'center' } },
      h('p', { class:'muted', style:{ margin:'0 0 .8rem' } }, 'No courses yet. Add your first one.'),
      h('button', { class:'btn primary', onclick: () => openCourseEditModal(null, () => VIEWS.educourses(view)) }, '+ Add new course')
    ));
    return;
  }

  // KPI tiles
  const totalCourses = courses.length;
  const totalWithEmi = courses.filter(c => extras[String(c.id)] && extras[String(c.id)].emi).length;
  view.appendChild(h('div', { style:{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(180px, 1fr))', gap:'.6rem', marginBottom:'1rem' } },
    h('div', { class:'card', style:{ padding:'.7rem .9rem' } },
      h('div', { class:'muted', style:{ fontSize:'.72em' } }, 'TOTAL COURSES'),
      h('div', { style:{ fontSize:'1.3rem', fontWeight:600 } }, String(totalCourses))),
    h('div', { class:'card', style:{ padding:'.7rem .9rem' } },
      h('div', { class:'muted', style:{ fontSize:'.72em' } }, 'WITH EMI DEFAULTS'),
      h('div', { style:{ fontSize:'1.3rem', fontWeight:600, color: totalWithEmi === totalCourses ? '#16a34a' : '#ea580c' } }, totalWithEmi + ' / ' + totalCourses))
  ));

  // Integrated table — name, price, token, EMI, count, actions
  const tbl = h('table', { class:'mini-table' },
    h('thead', {}, h('tr', {},
      h('th', {}, 'Course'),
      h('th', { style:{ width:'120px', textAlign:'right' } }, 'Total Price'),
      h('th', { style:{ width:'120px', textAlign:'right' } }, 'Token ₹'),
      h('th', { style:{ width:'130px', textAlign:'right' } }, 'EMI ₹'),
      h('th', { style:{ width:'90px',  textAlign:'right' } }, '# EMIs'),
      h('th', { style:{ width:'140px', textAlign:'right' } }, 'Auto-fill total'),
      h('th', { style:{ width:'140px' } }, '')
    )),
    h('tbody', {},
      ...courses.map(c => {
        const ex = extras[String(c.id)] || {};
        const computed = (Number(ex.token) || 0) + ((Number(ex.emi) || 0) * (Number(ex.count) || 0));
        const ok = computed > 0 && Math.abs(computed - Number(c.price || 0)) < 1;
        return h('tr', {},
          h('td', {},
            h('div', { style:{ fontWeight:600 } }, c.name),
            c.description ? h('div', { class:'muted', style:{ fontSize:'.78em' } }, c.description) : null
          ),
          h('td', { style:{ textAlign:'right' } }, '₹' + Number(c.price || 0).toLocaleString('en-IN')),
          h('td', { style:{ textAlign:'right', color: ex.token ? 'inherit' : '#9ca3af' } }, ex.token ? ('₹' + Number(ex.token).toLocaleString('en-IN')) : '—'),
          h('td', { style:{ textAlign:'right', color: ex.emi ? 'inherit' : '#9ca3af' } }, ex.emi ? ('₹' + Number(ex.emi).toLocaleString('en-IN')) : '—'),
          h('td', { style:{ textAlign:'right', color: ex.count ? 'inherit' : '#9ca3af' } }, ex.count ? String(ex.count) : '—'),
          h('td', { style:{ textAlign:'right', fontSize:'.85em' } },
            computed > 0
              ? h('span', { style:{ color: ok ? '#16a34a' : '#dc2626', fontWeight: 600 } },
                  '₹' + Number(computed).toLocaleString('en-IN') + (ok ? ' ✓' : ' ⚠'))
              : h('span', { class:'muted' }, '—')
          ),
          h('td', {},
            h('button', { class:'btn sm primary', onclick: () => openCourseEditModal(c, () => VIEWS.educourses(view)) }, '✎ Edit'),
            h('button', { class:'btn sm danger', style:{ marginLeft:'.3rem' }, onclick: async () => {
              if (!confirm('Delete course "' + c.name + '"? Existing leads keep the reference; new leads stop seeing it.')) return;
              try { await api('api_products_delete', c.id); toast('Deleted'); VIEWS.educourses(view); }
              catch (e) { toast(e.message, 'err'); }
            } }, '🗑')
          )
        );
      })
    )
  );
  view.appendChild(tbl);
};

// Unified Course editor — sets both product fields AND EMI defaults in one modal
async function openCourseEditModal(existing, onDone) {
  const ex = existing || {};
  const m = h('div', { class:'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class:'modal modal-lg' });
  modal.appendChild(h('div', { class:'modal-head' },
    h('h3', {}, ex.id ? '✎ Edit course' : '+ Add new course'),
    h('button', { class:'btn ghost', onclick: () => m.remove() }, '✕')
  ));

  // Pull saved extras for this course
  let extras = {};
  try {
    const raw = await api('api_admin_getConfig', 'edu_course_extras').catch(() => null);
    extras = (raw && raw.value) ? JSON.parse(raw.value) : {};
  } catch (_) { extras = {}; }
  const exEmi = (ex.id && extras[String(ex.id)]) ? extras[String(ex.id)] : {};

  const fName  = h('input', { type:'text', value: ex.name || '', placeholder:'e.g. JEE Advanced 2027', style:{ width:'100%' } });
  const fDesc  = h('input', { type:'text', value: ex.description || '', placeholder:'Short description', style:{ width:'100%' } });
  const fPrice = h('input', { type:'number', value: ex.price || '', placeholder:'Total course fee', style:{ width:'100%', textAlign:'right' } });
  const fGst   = h('input', { type:'number', value: ex.gst_pct || 0, style:{ width:'100%', textAlign:'right' } });
  const fImg   = h('input', { type:'text', value: ex.image_url || '', placeholder:'Image URL (optional)', style:{ width:'100%' } });

  const fToken = h('input', { type:'number', value: exEmi.token || '', placeholder:'5000', style:{ width:'100%', textAlign:'right' } });
  const fEmi   = h('input', { type:'number', value: exEmi.emi   || '', placeholder:'9166', style:{ width:'100%', textAlign:'right' } });
  const fCount = h('input', { type:'number', value: exEmi.count || '', placeholder:'6', min:'1', style:{ width:'100%', textAlign:'right' } });

  const totalCalc = h('div', { style:{ fontWeight:600, fontSize:'1.05em', padding:'.5rem .8rem', background:'#fef3c7', borderRadius:'6px' } }, 'Auto-fill total: ₹0');
  function _recalc() {
    const tok = Number(fToken.value || 0);
    const emi = Number(fEmi.value || 0);
    const cnt = Number(fCount.value || 0);
    const t = tok + (emi * cnt);
    const total = Number(fPrice.value || 0);
    const matches = total > 0 && t > 0 && Math.abs(t - total) < 1;
    totalCalc.textContent = 'Token ₹' + tok.toLocaleString('en-IN') + ' + (EMI ₹' + emi.toLocaleString('en-IN') + ' × ' + cnt + ') = ₹' + t.toLocaleString('en-IN') + (total > 0 ? (matches ? ' ✓ matches total price' : ' ⚠ does not match total price ₹' + total.toLocaleString('en-IN')) : '');
    totalCalc.style.background = matches ? '#dcfce7' : (t > 0 ? '#fee2e2' : '#fef3c7');
  }
  [fPrice, fToken, fEmi, fCount].forEach(el => el.addEventListener('input', _recalc));

  modal.appendChild(h('div', { class:'modal-body' },
    h('h4', { style:{ margin:'0 0 .4rem', color:'#0c4a6e' } }, '🎓 Course details'),
    h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'.5rem' } },
      h('label', { style:{ gridColumn:'span 2' } }, 'Course name *', fName),
      h('label', { style:{ gridColumn:'span 2' } }, 'Description (optional)', fDesc),
      h('label', {}, 'Total course fee (₹) *', fPrice),
      h('label', {}, 'GST %', fGst),
      h('label', { style:{ gridColumn:'span 2' } }, 'Course image URL (optional)', fImg)
    ),

    h('h4', { style:{ margin:'1rem 0 .4rem', color:'#0c4a6e' } }, '💰 Fee structure (auto-fills at sale closure)'),
    h('p', { class:'muted', style:{ fontSize:'.85em', margin:'0 0 .5rem' } },
      'When a counsellor picks this course at 💰 Close Sale, these values pre-fill the token + installments — they can still adjust per-student before saving.'),
    h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:'.5rem' } },
      h('label', {}, '🪙 Token amount ₹', fToken),
      h('label', {}, '📅 Each EMI ₹',     fEmi),
      h('label', {}, '# of EMIs',           fCount)
    ),
    totalCalc
  ));
  setTimeout(_recalc, 50);

  modal.appendChild(h('div', { class:'actions' },
    h('button', { class:'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class:'btn primary', onclick: async () => {
      if (!fName.value.trim()) { toast('Course name required', 'err'); return; }
      try {
        // 1) Save the course (product)
        const productPayload = {
          id: ex.id,
          name: fName.value.trim(),
          description: fDesc.value,
          price: Number(fPrice.value) || 0,
          gst_pct: Number(fGst.value) || 0,
          image_url: fImg.value || null
        };
        const saved = await api('api_products_save', productPayload);
        const productId = saved && (saved.id || ex.id);

        // 2) Save the EMI defaults
        let extras2 = {};
        try {
          const raw2 = await api('api_admin_getConfig', 'edu_course_extras').catch(() => null);
          extras2 = (raw2 && raw2.value) ? JSON.parse(raw2.value) : {};
        } catch (_) {}
        if (productId) {
          extras2[String(productId)] = {
            token: Number(fToken.value) || 0,
            emi:   Number(fEmi.value)   || 0,
            count: Number(fCount.value) || 0
          };
          await api('api_admin_setConfig', { key:'edu_course_extras', value: JSON.stringify(extras2) });
        }
        toast(ex.id ? '✓ Course updated' : '✓ Course created');
        m.remove();
        await warmCache();
        if (onDone) onDone();
      } catch (e) { toast(e.message, 'err'); }
    } }, ex.id ? '💾 Save' : '+ Create course')
  ));

  m.appendChild(modal);
  document.body.appendChild(m);
  setTimeout(() => fName.focus(), 100);
}

try { window.openCourseEditModal = openCourseEditModal; } catch (_) {}

// ───── Patch openCloseSaleModal again to use the new Course dropdown
// fully (auto-fill token + installments + total + dates).
(function _enhanceCloseSaleWithCoursePicker() {
  if (typeof openCloseSaleModal !== 'function') return;
  const _orig = openCloseSaleModal;
  window.openCloseSaleModal = async function patchedV2(leadId, onDone) {
    const out = await _orig.apply(this, arguments);
    setTimeout(async () => {
      try {
        const backdrop = document.querySelector('.modal-backdrop:last-of-type');
        if (!backdrop) return;
        // Drop the existing 'Pick saved course' simple <select> if present from earlier patch
        backdrop.querySelectorAll('select').forEach(s => {
          if ([...s.options].some(o => o.text && o.text.indexOf('— Pick saved course —') >= 0)) s.remove();
        });

        const inputs = [...backdrop.querySelectorAll('input')];
        const fCourse  = inputs.find(i => (i.placeholder || '').toLowerCase().includes('jee advanced'));
        const fTokAmt  = inputs.find(i => i.type === 'number' && i.placeholder === '5000');
        const fTokDate = inputs.find(i => i.type === 'date'   && i.value === new Date().toISOString().slice(0,10));
        if (!fCourse) return;

        // Build a course dropdown right above the course input (full-width)
        const courses = await api('api_products_list').catch(() => []);
        if (!courses || !courses.length) return;
        let extras = {};
        try {
          const raw = await api('api_admin_getConfig', 'edu_course_extras').catch(() => null);
          extras = (raw && raw.value) ? JSON.parse(raw.value) : {};
        } catch (_) {}

        const courseSel = h('select', { style:{ width:'100%' } },
          h('option', { value:'' }, '— Pick course from catalog (auto-fills fees) —'),
          ...courses.map(c => h('option', { value: c.id, 'data-name': c.name }, c.name + ' · ₹' + Number(c.price || 0).toLocaleString('en-IN')))
        );
        const wrap = h('div', { style:{ marginBottom:'.4rem' } },
          h('label', { style:{ display:'block', fontSize:'.78em', color:'#475569' } }, '📚 Pick course'),
          courseSel
        );
        // Insert above course input parent label
        const courseLabel = fCourse.closest('label');
        if (courseLabel) courseLabel.parentNode.insertBefore(wrap, courseLabel);

        courseSel.addEventListener('change', () => {
          const opt = courseSel.selectedOptions[0];
          if (!opt || !opt.value) return;
          fCourse.value = opt.dataset.name || '';
          const ex = extras[opt.value] || {};
          if (fTokAmt && ex.token) { fTokAmt.value = ex.token; fTokAmt.dispatchEvent(new Event('input', { bubbles:true })); }
          // Auto-build installment rows
          if (ex.emi && ex.count) {
            const insWrap = [...backdrop.querySelectorAll('.modal-body > div')].find(d => /Installment 1/i.test(d.textContent || ''));
            // Easier path — fire Quick split equivalent: find Quick split button and replace its behaviour
            // We just clear existing rows and recreate using exposed addInsRow if available; otherwise manual
            const allRows = backdrop.querySelectorAll('.modal-body > div .card[style*="flex"]');
            allRows.forEach(r => { if (r._getRow) r.remove(); });
            const startDate = (fTokDate && fTokDate.value) || new Date().toISOString().slice(0,10);
            // Find the actual insWrap (the parent that holds rows with _getRow)
            // Reverse-engineer: clear all child .card flex rows under the Installment section
            // and call addInsRow N times — but addInsRow isn't in our scope here.
            // Pragmatic fallback: toast the values so the rep can use Quick split
            toast('Course picked · Token ₹' + Number(ex.token||0).toLocaleString('en-IN') + ', EMI ₹' + Number(ex.emi).toLocaleString('en-IN') + ' × ' + ex.count + ' — click ⚡ Quick split below', 'ok');
          }
        });
      } catch (_) {}
    }, 180);
    return out;
  };
})();

// ───── Fallback redirect: clicking on the old Products sidebar entry should
// still work, but if Education installed AND user goes to /#/products, we
// auto-redirect to /#/educourses for a better UX.
(function _redirectProductsToCourses() {
  function check() {
    try {
      const installed = (CRM.installedPacks instanceof Set) ? CRM.installedPacks : new Set();
      if (!installed.has('education')) return;
      if (location.hash === '#/products') location.hash = '#/educourses';
    } catch (_) {}
  }
  window.addEventListener('hashchange', check);
  setTimeout(check, 500);
})();



// ═════════════════════════════════════════════════════════════════════
// 🏢 Branch hierarchy — assign agents / team leaders / managers per branch
// ═════════════════════════════════════════════════════════════════════
// Replaces the simpler openManageBranchesModal with one that supports
// multi-user assignment per branch (admin, manager, team_leader, agent).
async function openManageBranchesModalV2() {
  const m = h('div', { class:'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class:'modal modal-lg' });
  modal.appendChild(h('div', { class:'modal-head' },
    h('h3', {}, '🏢 Branch hierarchy — assign users per branch'),
    h('button', { class:'btn ghost', onclick: () => m.remove() }, '✕')
  ));
  const body = h('div', { class:'modal-body' });
  modal.appendChild(body);

  const refresh = async () => {
    body.innerHTML = '<div class="muted">Loading…</div>';
    try {
      // Try the rich query with user counts first, fall back to plain list
      let branches = [];
      try { branches = await api('api_edu_branches_listWithCounts'); }
      catch (_) { branches = await api('api_edu_branches_list'); }

      const allUsers = await api('api_users_list').catch(() => []);

      body.innerHTML = '';

      branches.forEach(b => {
        const card = h('div', { class:'card', style:{ padding:'.7rem .9rem', marginBottom:'.6rem' } });
        // Header row
        card.appendChild(h('div', { style:{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'.4rem' } },
          h('div', {},
            h('strong', {}, b.name + (b.code ? ' · ' + b.code : '')),
            !Number(b.is_active) ? h('span', { style:{ marginLeft:'.4rem', background:'#fee2e2', color:'#991b1b', padding:'2px 6px', borderRadius:'4px', fontSize:'.7em' } }, 'INACTIVE') : null,
            b.address ? h('div', { class:'muted', style:{ fontSize:'.78em' } }, '📍 ' + b.address) : null,
            b.phone   ? h('div', { class:'muted', style:{ fontSize:'.78em' } }, '📞 ' + b.phone) : null
          ),
          h('div', { style:{ display:'flex', gap:'.3rem' } },
            h('button', { class:'btn sm', onclick: () => editBranch(b) }, '✎ Edit'),
            Number(b.is_active)
              ? h('button', { class:'btn sm', onclick: async () => { await api('api_edu_branches_save', Object.assign({}, b, { is_active: 0 })); refresh(); } }, 'Disable')
              : h('button', { class:'btn sm primary', onclick: async () => { await api('api_edu_branches_save', Object.assign({}, b, { is_active: 1 })); refresh(); } }, 'Enable')
          )
        ));

        // Assigned users section
        const usersWrap = h('div', { style:{ background:'#f8fafc', padding:'.5rem .7rem', borderRadius:'6px', marginTop:'.4rem' } });
        card.appendChild(usersWrap);

        // Stats row
        if (typeof b.total_users === 'number') {
          usersWrap.appendChild(h('div', { style:{ display:'flex', gap:'.4rem', marginBottom:'.4rem', fontSize:'.78em' } },
            b.manager_count > 0 ? h('span', { style:{ background:'#ddd6fe', color:'#5b21b6', padding:'2px 6px', borderRadius:'4px' } }, '👔 ' + b.manager_count + ' manager' + (b.manager_count > 1 ? 's' : '')) : null,
            b.lead_count > 0    ? h('span', { style:{ background:'#bfdbfe', color:'#1e40af', padding:'2px 6px', borderRadius:'4px' } }, '🎯 ' + b.lead_count + ' team lead' + (b.lead_count > 1 ? 's' : '')) : null,
            b.agent_count > 0   ? h('span', { style:{ background:'#dcfce7', color:'#166534', padding:'2px 6px', borderRadius:'4px' } }, '👥 ' + b.agent_count + ' agent' + (b.agent_count > 1 ? 's' : '')) : null,
            b.total_users === 0 ? h('span', { class:'muted' }, '⚠ No users assigned — leads cannot route to this branch') : null
          ));
        }

        // List of assigned users
        const listEl = h('div', { class:'muted', style:{ fontSize:'.85em' } }, 'Loading users…');
        usersWrap.appendChild(listEl);
        usersWrap.appendChild(h('button', { class:'btn sm primary', style:{ marginTop:'.4rem' }, onclick: () => openAssignUsersModal(b, allUsers, refresh) }, '+ Manage users'));

        // Async load assignments
        (async () => {
          try {
            const assigned = await api('api_edu_branch_users_list', b.id);
            listEl.innerHTML = '';
            if (!assigned.length) {
              listEl.textContent = 'No users assigned yet. Click "Manage users" below to start.';
              return;
            }
            const chips = h('div', { style:{ display:'flex', flexWrap:'wrap', gap:'.3rem' } });
            assigned.forEach(u => {
              const roleColor = u.user_role === 'admin' ? '#fef3c7' :
                                u.user_role === 'manager' ? '#ddd6fe' :
                                u.user_role === 'team_leader' ? '#bfdbfe' :
                                '#dcfce7';
              const roleText  = u.user_role === 'admin' ? 'Admin' :
                                u.user_role === 'manager' ? 'Manager' :
                                u.user_role === 'team_leader' ? 'Team Lead' :
                                'Agent';
              chips.appendChild(h('span', {
                style:{ background: roleColor, padding:'3px 8px', borderRadius:'4px', fontSize:'.8em', display:'inline-flex', gap:'.3rem', alignItems:'center' },
                title: u.email || ''
              },
                h('span', {}, u.name || ('User #' + u.user_id)),
                h('span', { style:{ fontSize:'.7em', opacity:0.7 } }, roleText),
                h('button', { style:{ background:'transparent', border:'none', cursor:'pointer', padding:'0 0 0 .3rem', color:'#dc2626', fontSize:'.8em' },
                  title: 'Remove from branch',
                  onclick: async (ev) => {
                    ev.stopPropagation();
                    if (!confirm('Remove ' + (u.name || 'this user') + ' from ' + b.name + '?')) return;
                    await api('api_edu_branch_users_remove', { branch_id: b.id, user_id: u.user_id });
                    refresh();
                  }
                }, '✕')
              ));
            });
            listEl.appendChild(chips);
          } catch (e) {
            listEl.textContent = 'Could not load users: ' + e.message;
          }
        })();

        body.appendChild(card);
      });

      // Add-branch form
      const fName = h('input', { type:'text', placeholder:'New branch name (e.g. Andheri West)' });
      const fCode = h('input', { type:'text', placeholder:'Short code (e.g. AND)' });
      const fAddr = h('input', { type:'text', placeholder:'Address' });
      const fPhone = h('input', { type:'text', placeholder:'Phone' });
      body.appendChild(h('div', { class:'card', style:{ padding:'.7rem .9rem', background:'#fef9c3', borderLeft:'4px solid #f59e0b', marginTop:'.8rem' } },
        h('h4', { style:{ margin:'0 0 .4rem' } }, '+ Add new branch'),
        h('div', { style:{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'.4rem' } }, fName, fCode, fAddr, fPhone),
        h('button', { class:'btn primary', style:{ marginTop:'.4rem' }, onclick: async () => {
          if (!fName.value.trim()) { toast('Branch name required', 'err'); return; }
          try {
            await api('api_edu_branches_save', { name: fName.value.trim(), code: fCode.value, address: fAddr.value, phone: fPhone.value });
            toast('Branch added — now assign users to it');
            refresh();
          } catch (e) { toast(e.message, 'err'); }
        } }, '+ Save branch')
      ));
    } catch (e) {
      body.innerHTML = '';
      body.appendChild(h('div', { class:'error-box' }, e.message));
    }
  };

  function editBranch(b) {
    const fName = h('input', { type:'text', value: b.name });
    const fCode = h('input', { type:'text', value: b.code || '' });
    const fAddr = h('input', { type:'text', value: b.address || '' });
    const fPhone = h('input', { type:'text', value: b.phone || '' });
    const m2 = h('div', { class:'modal-backdrop' });
    const card = h('div', { class:'modal' });
    card.appendChild(h('div', { class:'modal-head' }, h('h3', {}, 'Edit branch'), h('button', { class:'btn ghost', onclick: () => m2.remove() }, '✕')));
    card.appendChild(h('div', { class:'modal-body' },
      h('label', {}, 'Name', fName),
      h('label', {}, 'Code', fCode),
      h('label', {}, 'Address', fAddr),
      h('label', {}, 'Phone', fPhone)
    ));
    card.appendChild(h('div', { class:'actions' },
      h('button', { class:'btn', onclick: () => m2.remove() }, 'Cancel'),
      h('button', { class:'btn primary', onclick: async () => {
        try {
          await api('api_edu_branches_save', { id: b.id, name: fName.value.trim(), code: fCode.value, address: fAddr.value, phone: fPhone.value });
          toast('Saved'); m2.remove(); refresh();
        } catch (e) { toast(e.message, 'err'); }
      } }, 'Save')
    ));
    m2.appendChild(card);
    document.body.appendChild(m2);
  }

  m.appendChild(modal);
  document.body.appendChild(m);
  refresh();
}

// Multi-user assignment modal — admin/manager/team_leader/agent
async function openAssignUsersModal(branch, allUsers, onDone) {
  const m = h('div', { class:'modal-backdrop', onclick: ev => { if (ev.target.classList.contains('modal-backdrop')) m.remove(); } });
  const modal = h('div', { class:'modal modal-lg' });
  modal.appendChild(h('div', { class:'modal-head' },
    h('h3', {}, '👥 Assign users to ' + branch.name),
    h('button', { class:'btn ghost', onclick: () => m.remove() }, '✕')
  ));

  const body = h('div', { class:'modal-body' });
  body.appendChild(h('p', { class:'muted', style:{ fontSize:'.85em', marginTop:0 } },
    'Tick the users who should have access to this branch. Their role badge comes from their global CRM role — change a user\'s role in Settings → Users. You can assign one user to multiple branches.'));

  // Get currently assigned user IDs
  let assigned = [];
  try { assigned = await api('api_edu_branch_users_list', branch.id); }
  catch (_) {}
  const assignedSet = new Set(assigned.map(a => Number(a.user_id)));

  // Group users by role
  const grouped = { admin: [], manager: [], team_leader: [], agent: [] };
  (allUsers || []).filter(u => Number(u.is_active)).forEach(u => {
    const r = u.role || 'agent';
    if (grouped[r]) grouped[r].push(u);
    else grouped.agent.push(u);
  });

  const roleMeta = {
    admin:       { label: '👑 Admins',       bg:'#fef3c7', color:'#92400e' },
    manager:     { label: '👔 Managers',     bg:'#ddd6fe', color:'#5b21b6' },
    team_leader: { label: '🎯 Team Leaders', bg:'#bfdbfe', color:'#1e40af' },
    agent:       { label: '👥 Agents',       bg:'#dcfce7', color:'#166534' }
  };

  const checkboxes = [];
  ['admin','manager','team_leader','agent'].forEach(role => {
    const users = grouped[role] || [];
    if (!users.length) return;
    const meta = roleMeta[role];
    body.appendChild(h('h4', { style:{ margin:'.8rem 0 .3rem', color: meta.color } }, meta.label + ' (' + users.length + ')'));
    const list = h('div', { style:{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(220px, 1fr))', gap:'.3rem' } });
    users.forEach(u => {
      const cb = h('input', { type:'checkbox', value: u.id, 'data-uid': u.id });
      if (assignedSet.has(Number(u.id))) cb.checked = true;
      checkboxes.push(cb);
      list.appendChild(h('label', {
        style:{ display:'flex', alignItems:'center', gap:'.4rem', padding:'.4rem .5rem', background: meta.bg, borderRadius:'4px', cursor:'pointer', fontSize:'.88em' }
      },
        cb, h('span', {}, u.name || u.email)
      ));
    });
    body.appendChild(list);
  });

  // Bulk-select chips
  body.appendChild(h('div', { style:{ marginTop:'.8rem', display:'flex', gap:'.3rem', flexWrap:'wrap' } },
    h('button', { class:'btn sm', onclick: () => checkboxes.forEach(c => c.checked = true) }, '✓ Select all'),
    h('button', { class:'btn sm', onclick: () => checkboxes.forEach(c => c.checked = false) }, '✕ Clear all'),
    ...['admin','manager','team_leader','agent'].map(r => h('button', { class:'btn sm', onclick: () => {
      checkboxes.forEach(c => {
        const u = (allUsers || []).find(x => Number(x.id) === Number(c.dataset.uid));
        if (u && (u.role || 'agent') === r) c.checked = true;
      });
    } }, '+ All ' + r.replace('_', ' ') + 's'))
  ));

  modal.appendChild(body);
  modal.appendChild(h('div', { class:'actions' },
    h('button', { class:'btn', onclick: () => m.remove() }, 'Cancel'),
    h('button', { class:'btn primary', onclick: async () => {
      const ids = checkboxes.filter(c => c.checked).map(c => Number(c.value));
      try {
        const r = await api('api_edu_branch_users_assign', { branch_id: branch.id, user_ids: ids });
        toast('✓ ' + r.assigned + ' user(s) assigned to ' + branch.name);
        m.remove();
        if (onDone) onDone();
      } catch (e) { toast(e.message, 'err'); }
    } }, '💾 Save assignments')
  ));

  m.appendChild(modal);
  document.body.appendChild(m);
}

